import { createContext, useState, useEffect, useCallback } from 'react';
import { AuthService } from '../services/auth.service';
import { CONFIG } from '../config/env';
import { api } from '../config/axios';

import { useContext } from 'react';

export const AuthContext = createContext(null);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth debe ser usado dentro de un AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [permisos, setPermisos] = useState(null);

  // Cargar permisos del rol desde el backend
  const cargarPermisosRol = useCallback(async (userData) => {
    // Probar varias fuentes posibles para el id del rol
    const idRol = userData?.id_fkrol_usuario || userData?.id_rol || userData?.rol;
    if (idRol) {
      try {
        const res = await api.post('/roles/selectRolesAcciones', { id_rol: idRol });
        if (res.data?.success && res.data?.data?.length > 0 && res.data.data[0]?.descripcion_rol) {
          const parsed = JSON.parse(res.data.data[0].descripcion_rol);
          setPermisos(parsed);
          return;
        }
      } catch (err) {
        console.warn('No se pudieron cargar los permisos del rol:', err);
      }
    }
    // Fallback: si no se cargaron permisos pero el usuario es admin numérico (rol 5), activar todo
    if (userData?.rol_usuario === 5 || userData?.rol === 5) {
      setPermisos(null); // null hará que hasPermission devuelva true para admin
    }
  }, []);

  // Inicializar estado desde sessionStorage
  useEffect(() => {
    const token = sessionStorage.getItem('auth_token');
    const userDataStr = sessionStorage.getItem('user_data');

    if (token && userDataStr) {
      try {
        const userData = JSON.parse(userDataStr);
        setUser(userData);
        setIsAuthenticated(true);
        cargarPermisosRol(userData);
      } catch (e) {
        console.error('Error parsing user data from session storage', e);
        logout();
      }
    }
    setLoading(false);
  }, []);

  const login = async (username, password) => {
    try {
      const loginData = await AuthService.login(username, password);

      if (loginData.success) {
        // 1. Guardar tokens y URL de backend
        sessionStorage.setItem('auth_token', loginData.token);
        sessionStorage.setItem('refresh_token', loginData.refresh_token);
        const backendUrlToUse = loginData.backend_url || CONFIG.AUTH_API_URL;
        sessionStorage.setItem('backend_url', backendUrlToUse);
        sessionStorage.setItem('user_data', JSON.stringify(loginData.user));

        // 2. Puente PHP
        await AuthService.phpSessionBridge(loginData);

        // 3. Actualizar estado y cargar permisos del rol
        setUser(loginData.user);
        setIsAuthenticated(true);
        cargarPermisosRol(loginData.user);

        return { success: true };
      } else {
        return { success: false, message: loginData.mensaje || 'Credenciales inválidas' };
      }
    } catch (error) {
      console.error('Login error', error);
      let message = 'Hubo un error en el servidor. Por favor, contacte con soporte.';
      if (error.code === 'ECONNABORTED' || error.message === 'Network Error') {
        message = 'No se pudo conectar con el servidor. Verifique su conexión a internet.';
      }
      return { success: false, message };
    }
  };

  // Verificar si el usuario tiene un rol específico
  const hasRole = useCallback((roleName) => {
    if (!user) return false;
    // El usuario puede tener roles como array de strings o como array de objetos {nombre, ...}
    const userRoles = user.roles || user.role || [];
    if (Array.isArray(userRoles)) {
      return userRoles.some(r => {
        if (typeof r === 'string') return r.toLowerCase() === roleName.toLowerCase();
        if (r && r.nombre) return r.nombre.toLowerCase() === roleName.toLowerCase();
        return false;
      });
    }
    return typeof userRoles === 'string' && userRoles.toLowerCase() === roleName.toLowerCase();
  }, [user]);

  // Verificar si el usuario tiene permiso por módulo
  const hasPermission = useCallback((permission) => {
    if (!user) return false;
    // Admin por rol numérico (5) o por nombre tiene todos los permisos
    if (hasRole('admin') || hasRole('administrador') || user.rol_usuario === 5) return true;
    // Si permisos es null significa admin fallback
    if (permisos === null) return true;

    // Prioridad: permisos cargados del backend > user.permisos del auth service
    const sourcePermisos = permisos || user.permisos || user.permissions || user.descripcion_rol || {};

    // Si es un string JSON (viene de /buscarUsuario), parsearlo
    const parsedPermisos = typeof sourcePermisos === 'string' ? (() => {
      try { return JSON.parse(sourcePermisos); } catch { return {}; }
    })() : sourcePermisos;

    // Soporte para notación "modulo.permiso" (ej. "administracion.gestion_usuarios")
    if (permission && typeof permission === 'string' && permission.includes('.')) {
      const [mod, perm] = permission.split('.');
      return parsedPermisos[mod]?.[perm] === true;
    }

    // Soporte legacy: array de strings u objetos
    if (Array.isArray(parsedPermisos)) {
      return parsedPermisos.some(p => {
        if (typeof p === 'string') return p === permission;
        if (p && p.modulo) return p.modulo === permission;
        return false;
      });
    }

    return false;
  }, [user, hasRole, permisos]);

  // Nombre del usuario para mostrar
  const userName = user?.nombre || user?.username || user?.usuario || '';
  const userRole = user?.rol || user?.role || user?.roles || '';

  // Suplantación: Login como otro usuario desde el panel de administración
  const loginFromImpersonation = useCallback(async (token, userData, bridgeData) => {
    // 1. Guardar en sessionStorage exactamente como login normal
    sessionStorage.setItem('auth_token', token);
    sessionStorage.setItem('user_data', JSON.stringify(userData));
    if (bridgeData.refresh_token) {
      sessionStorage.setItem('refresh_token', bridgeData.refresh_token);
    }
    if (bridgeData.backend_url) {
      sessionStorage.setItem('backend_url', bridgeData.backend_url);
    }

    // 2. Puente PHP (sesión legacy)
    await AuthService.phpSessionBridge(bridgeData);

    // 3. Actualizar estado React
    setUser(userData);
    setIsAuthenticated(true);

    // 4. Cargar permisos del rol del usuario suplantado
    cargarPermisosRol(userData);
  }, [cargarPermisosRol]);

  const logout = useCallback(() => {
    sessionStorage.clear();
    setUser(null);
    setIsAuthenticated(false);
    window.location.href = '/#/login';
  }, []);

  return (
    <AuthContext.Provider value={{ user, isAuthenticated, loading, login, logout, loginFromImpersonation, hasRole, hasPermission, userName, userRole }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

import { useEffect, useState } from 'react';
import { io } from 'socket.io-client';
import toast from 'react-hot-toast';
import { CONFIG } from '../config/env';
import { useAuth } from './useAuth';

export const useSocket = () => {
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const { user, isAuthenticated, logout } = useAuth();

  useEffect(() => {
    if (!isAuthenticated || !user) return;

    // Conectar usando la baseURL asignada
    const backendUrl = CONFIG.API_URL;
    if (!backendUrl) return;

    const token = sessionStorage.getItem('auth_token');

    const newSocket = io(backendUrl, {
      auth: token ? { token } : undefined,
      withCredentials: true,
      transports: ['polling', 'websocket'],
      reconnection: true,
      reconnectionAttempts: 20,
      reconnectionDelay: 3000
    });

    setSocket(newSocket);
    // Exponer socket globalmente para que cualquier componente pueda emitir eventos
    window.__socket = newSocket;

    newSocket.on('connect', () => {
      setIsConnected(true);
      console.log('Socket conectado:', newSocket.id);

      // Registrar al usuario en el socket
      newSocket.emit('register_user', {
        id_usuario: user.id_usuario,
        id_rol: user.id_rol,
        id_sucursal: user.id_sucursal,
        id_terminal: user.id_terminal || 1 // O de donde venga en React
      });
    });

    newSocket.on('disconnect', () => {
      setIsConnected(false);
      console.log('Socket desconectado');
    });

    newSocket.on('connect_error', (err) => {
      setIsConnected(false);
      console.error('Socket connect_error:', err?.message || err);
    });

    // Evento legacy de force logout
    newSocket.on('force_logout', (data) => {
       console.log('Force logout via socket:', data);
       logout();
    });

    // ─── NOTIFICACIÓN: Sucursal cambió de ciudad ──────────────────────────
    newSocket.on('sucursal_ciudad_changed', (data) => {
      console.log('[Socket] Sucursal cambió de ciudad:', data);
      // Solo un toast aunque hayan dos conexiones socket por el id único
      const msg = `🏢 ¡Ciudad de sucursal actualizada!\n${data.nombre_sucursal} cambió de ${data.ciudad_vieja} a ${data.ciudad_nueva}.\n⚠️ Los viajes asociados podrían verse afectados.`;
      toast.error(msg, {
        id: 'sucursal-ciudad-changed',
        duration: 8000,
        style: {
          background: '#fffbeb',
          border: '1px solid #fde68a',
          color: '#92400e',
          borderRadius: '12px',
          padding: '12px 16px',
          fontFamily: 'Outfit, sans-serif',
          fontSize: '13px',
          fontWeight: 500,
          whiteSpace: 'pre-line',
        },
      });
      // Disparar evento para que el header se actualice
      window.dispatchEvent(new CustomEvent('sucursal_ciudad_changed', { detail: data }));
    });

    // ─── BLOQUEO DE ASIENTOS EN TIEMPO REAL ───────────────────────────────
    // Un asiento fue bloqueado por alguien
    newSocket.on('asiento_bloqueado', (data) => {
      // Incluye: { id_viaje, asiento, usuario, lockedAt (timestamp) }
      window.dispatchEvent(new CustomEvent('asiento_bloqueado', { detail: data }));
    });

    // Un asiento fue liberado (por deselección, timeout, desconexión o admin)
    newSocket.on('asiento_liberado', (data) => {
      // Incluye: { id_viaje, asiento, usuario, motivo: 'deseleccion'|'timeout'|'desconexion'|'admin', liberadoPor? }
      window.dispatchEvent(new CustomEvent('asiento_liberado', { detail: data }));
    });

    // Rechazo de bloqueo (intentaste bloquear algo que ya estaba bloqueado)
    newSocket.on('asiento_bloqueo_rechazado', (data) => {
      window.dispatchEvent(new CustomEvent('asiento_bloqueo_rechazado', { detail: data }));
    });

    // Estado actualizado de todos los locks (para monitoreo)
    newSocket.on('locks_actualizados', (data) => {
      window.dispatchEvent(new CustomEvent('locks_actualizados', { detail: data }));
    });

    // ─── NOTIFICACIÓN: Reserva próxima a vencer ──────────────────────────
    newSocket.on('reserva_por_vencer', (data) => {
      console.log('[Socket] Reserva próxima a vencer:', data);
      // Disparar evento para que el header muestre la notificación
      window.dispatchEvent(new CustomEvent('reserva_por_vencer', { detail: data }));

      // También mostrar toast
      toast(data.mensaje, {
        id: `reserva-vencer-${data.id_boleto}`,
        duration: 10000,
        icon: '⏰',
        style: {
          background: '#fffbeb',
          border: '1px solid #fde68a',
          color: '#92400e',
          borderRadius: '12px',
          padding: '12px 16px',
          fontFamily: 'Outfit, sans-serif',
          fontSize: '12px',
          fontWeight: 500,
          whiteSpace: 'pre-line',
        },
      });
    });

    // ─── NOTIFICACIÓN: Reserva confirmada ────────────────────────────────
    newSocket.on('reserva_confirmada', (data) => {
      console.log('[Socket] Reserva confirmada:', data);
      window.dispatchEvent(new CustomEvent('reserva_confirmada', { detail: data }));

      toast(data.mensaje || `✅ Reserva #${data.id_boleto} confirmada`, {
        id: `reserva-confirmada-${data.id_boleto}`,
        duration: 6000,
        icon: '✅',
        style: {
          background: '#f0fdf4',
          border: '1px solid #bbf7d0',
          color: '#166534',
          borderRadius: '12px',
          padding: '12px 16px',
          fontFamily: 'Outfit, sans-serif',
          fontSize: '12px',
          fontWeight: 500,
        },
      });
    });

    // ─── BOLETO INSERTADO (en tiempo real) ────────────────────────────────
    newSocket.on('boleto_insertado', (data) => {
      console.log('[Socket] Boleto insertado/anulado:', data);

      if (!data || !data.id_viaje) return;

      // Disparar evento custom para que NuevoBoletoPage actualice los asientos
      window.dispatchEvent(new CustomEvent('boleto_insertado', { detail: data }));

      // Mostrar toast de notificación (solo si no es el propio usuario)
      const getSessionUser = () => {
        try {
          const userData = sessionStorage.getItem('user_data');
          if (userData) return JSON.parse(userData);
        } catch (e) {}
        try {
          const usuario = sessionStorage.getItem('usuario');
          if (usuario) return JSON.parse(usuario);
        } catch (e) {}
        return null;
      };
      const currentUser = getSessionUser();
      const esMismoUsuario = currentUser && data.usuario === currentUser.nombre_usuario;

      if (!esMismoUsuario && data.asientos && data.asientos.length > 0) {
        const asientosStr = data.asientos.map(a => a.asiento_boleto_detalle).join(', ');
        let msg;
        if (data.tipo === 'anulacion_reserva') {
          msg = `🔄 Reserva anulada - Viaje #${data.id_viaje}\nAsiento(s) liberado(s): ${asientosStr}`;
        } else if (data.tipo === 'reserva') {
          msg = `📌 Nueva reserva - Viaje #${data.id_viaje}\nAsiento(s): ${asientosStr}\nPor: ${data.usuario || 'N/A'}`;
        } else {
          msg = `🎫 Nuevo boleto - Viaje #${data.id_viaje}\nAsiento(s): ${asientosStr}\nVendido por: ${data.usuario || 'N/A'}`;
        }
        toast(msg, {
          id: `boleto-${data.id_boleto}-${data.tipo}`,
          duration: 6000,
          icon: data.tipo === 'anulacion_reserva' ? '🔄' : '🎫',
          style: {
            background: data.tipo === 'anulacion_reserva' ? '#f0fdf4' : '#fff7ed',
            border: data.tipo === 'anulacion_reserva' ? '1px solid #bbf7d0' : '1px solid #fed7aa',
            color: data.tipo === 'anulacion_reserva' ? '#166534' : '#9a3412',
            borderRadius: '12px',
            padding: '12px 16px',
            fontFamily: 'Outfit, sans-serif',
            fontSize: '12px',
            fontWeight: 500,
            whiteSpace: 'pre-line',
          },
        });
      }
    });

    return () => {
      newSocket.disconnect();
    };
  }, [isAuthenticated, user, logout]);

  return { socket, isConnected };
};

