                }}>
                  {tiempoRestante.pasado ? '-' : ''}{String(tiempoRestante.horas).padStart(2, '0')}:{String(tiempoRestante.minutos).padStart(2, '0')}:{String(tiempoRestante.segundos).padStart(2, '0')}
                </div>
