        )}

        {/* Seats */}
        <div className="bus-seats-grid" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          {renderPiso(pisosMapa[pisoActivo] || {}, pisoActivo)}
        </div>
