        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
          <div style={{ width: 10, height: 10, background: '#27ae60', borderRadius: 2 }}></div>
          <span style={{ color: '#27ae60' }}>Libre en parada</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
