import { useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { clienteApi } from '../../../config/axios';

const TIPOS_IDENTIFICACION = [
  { value: 'Cedula', label: 'Cédula' },
  { value: 'RUC', label: 'RUC' },
  { value: 'Pasaporte', label: 'Pasaporte' },
];

export const NuevoClienteModal = ({ isOpen, onClose, onClienteCreado, clienteInicial, isForcedEdit = false }) => {
  const [tipoIdentificacion, setTipoIdentificacion] = useState('Cedula');
  const [identificacion, setIdentificacion] = useState('');
  const [nombres, setNombres] = useState('');
  const [direccion, setDireccion] = useState('');
  const [celular, setCelular] = useState('');
  const [correo, setCorreo] = useState('');
  const [fechaNacimiento, setFechaNacimiento] = useState('');
  const [saving, setSaving] = useState(false);
  const [validacionId, setValidacionId] = useState(null); // null | { valido: bool, msg: string }

  // Cargar datos del cliente a editar cuando se abre el modal
  useEffect(() => {
    if (!isOpen) return;
    if (clienteInicial) {
      // Determinar tipo de identificación
      const id = clienteInicial.identificacion_cliente || clienteInicial.identificacion || '';
      const soloDigitos = id.replace(/\D/g, '');
      let tipo = 'Cedula';
      if (soloDigitos.length === 13) tipo = 'RUC';
      else if (id.length >= 5 && isNaN(id)) tipo = 'Pasaporte';

      setTipoIdentificacion(clienteInicial.tipo_identificacion_cliente || tipo);
      setIdentificacion(id);
      setNombres(clienteInicial.nombre_cliente || clienteInicial.nombres || '');
      setDireccion(clienteInicial.direccion_cliente || clienteInicial.direccion || '');
      setCelular(clienteInicial.telefono_cliente || clienteInicial.celular || '');
      setCorreo(clienteInicial.email_cliente || clienteInicial.correo || '');
      setFechaNacimiento(clienteInicial.fecha_nacimiento || clienteInicial.fechaNacimiento || '');
      setValidacionId(null);
    } else {
      resetForm();
    }
  }, [isOpen, clienteInicial]);

  const resetForm = () => {
    setTipoIdentificacion('Cedula');
    setIdentificacion('');
    setNombres('');
    setDireccion('');
    setCelular('');
    setCorreo('');
    setFechaNacimiento('');
    setValidacionId(null);
  };

  const esEdicion = !!clienteInicial;

  const validarIdentificacion = (tipo, valor) => {
    if (!valor) return null;
    const soloDigitos = valor.replace(/\D/g, '');
    switch (tipo) {
      case 'Cedula':
        if (soloDigitos.length !== 10) return { valido: false, msg: `La cédula debe tener 10 dígitos (tiene ${soloDigitos.length})` };
        return { valido: true, msg: 'Cédula válida' };
      case 'RUC':
        if (soloDigitos.length !== 13) return { valido: false, msg: `El RUC debe tener 13 dígitos (tiene ${soloDigitos.length})` };
        return { valido: true, msg: 'RUC válido' };
      case 'Pasaporte':
        if (valor.length < 5) return { valido: false, msg: `Debe tener al menos 5 caracteres (tiene ${valor.length})` };
        return { valido: true, msg: 'Pasaporte válido' };
      default:
        return null;
    }
  };

  const getEffectiveTipo = (id, currentTipo) => {
    const soloDigitos = id.replace(/\D/g, '');
    if (soloDigitos.length === 10) return 'Cedula';
    if (soloDigitos.length === 13) return 'RUC';
    return currentTipo;
  };

  const handleIdentificacionChange = (e) => {
    const val = e.target.value;
    setIdentificacion(val);
    const effectiveTipo = getEffectiveTipo(val, tipoIdentificacion);
    if (effectiveTipo !== tipoIdentificacion) setTipoIdentificacion(effectiveTipo);
    setValidacionId(validarIdentificacion(effectiveTipo, val));
  };

  const handleTipoChange = (e) => {
    const nuevoTipo = e.target.value;
    setTipoIdentificacion(nuevoTipo);
    setValidacionId(validarIdentificacion(nuevoTipo, identificacion));
  };

  const getMaxLength = () => {
    if (tipoIdentificacion === 'Cedula') return 10;
    if (tipoIdentificacion === 'RUC') return 13;
    return 20;
  };

  const handleGuardar = async () => {
    console.log('[NuevoClienteModal] Guardar cliente:', { tipoIdentificacion, identificacion, nombres, direccion, celular, correo, fechaNacimiento });
    if (!identificacion) { console.log('[NuevoClienteModal] ⛔ Validación: falta identificación'); toast.error('Ingrese la identificación'); return; }
    if (!nombres) { console.log('[NuevoClienteModal] ⛔ Validación: falta nombre'); toast.error('Ingrese los nombres'); return; }
    if (!celular) { console.log('[NuevoClienteModal] ⛔ Validación: falta celular'); toast.error('Ingrese el celular/teléfono'); return; }
    if (!correo) { console.log('[NuevoClienteModal] ⛔ Validación: falta correo'); toast.error('Ingrese el correo electrónico'); return; }
    console.log('[NuevoClienteModal] ✅ Validación pasó, enviando petición...');

    setSaving(true);
    try {
      const body = {
        tipo_identificacion_cliente: tipoIdentificacion,
        identificacion_cliente: identificacion,
        nombre_cliente: nombres,
        direccion_cliente: direccion,
        telefono_cliente: celular,
        email_cliente: correo,
        fecha_nacimiento: fechaNacimiento,
      };
      // Si es edición, incluir el id_cliente para que el backend actualice
      if (esEdicion) {
        body.id_cliente = clienteInicial.id_cliente;
      }
      const response = await clienteApi.post('/cliente/ingresarActualizarCliente', body);
      const data = response.data;
      if (data.success) {
        // tipo 3 = cliente ya existía, buscar su ID
        if (data.tipo === 3) {
          const searchRes = await clienteApi.get('/cliente/clientebusquedaIdentificacion', {
            params: { identificacion_busqueda: identificacion }
          });
          const searchData = searchRes.data;
          if (searchData.success && searchData.total > 0) {
            const existing = searchData.data[0];
            const nuevoCliente = {
              id_cliente: existing.id_cliente,
              identificacion_cliente: identificacion,
              nombre_cliente: existing.nombre_cliente,
              direccion_cliente: existing.direccion_cliente,
              telefono_cliente: existing.telefono_cliente,
              email_cliente: existing.email_cliente,
              fecha_nacimiento: existing.fecha_nacimiento,
            };
            onClienteCreado(nuevoCliente, esEdicion);
            resetForm();
            onClose();
            return;
          }
        }
        const clienteData = Array.isArray(data.data) ? data.data[0] : data.data || {};
        const nuevoCliente = {
          id_cliente: clienteData?.id_cliente || data.id_cliente,
          identificacion_cliente: identificacion,
          nombre_cliente: nombres,
          direccion_cliente: direccion,
          telefono_cliente: celular,
          email_cliente: correo,
          fecha_nacimiento: fechaNacimiento,
        };
        onClienteCreado(nuevoCliente, esEdicion);
        resetForm();
        onClose();
      } else {
        toast.error(data.message || 'Error al crear cliente');
      }
    } catch (err) {
      console.error('[NuevoClienteModal] Error:', err);
      toast.error('Error al conectar con el servidor de clientes');
    } finally {
      setSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div style={{
      position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
      background: 'rgba(0,0,0,0.5)', zIndex: 1000,
      display: 'flex', alignItems: 'center', justifyContent: 'center'
    }}>
      <div style={{
        background: 'white', borderRadius: 8, width: 500, maxWidth: '90%',
        boxShadow: '0 10px 40px rgba(0,0,0,0.2)', overflow: 'hidden'
      }}>
        <div style={{
          background: '#0a365d', color: 'white', padding: '12px 16px',
          fontSize: 15, fontWeight: 'bold', display: 'flex',
          justifyContent: 'space-between', alignItems: 'center'
        }}>
          <span><i className="fas fa-user-plus" style={{ marginRight: 8 }}></i>{esEdicion ? 'Actualizar Cliente' : 'Nuevo Cliente'}</span>
          {!isForcedEdit && (
            <button onClick={() => { resetForm(); onClose(); }}
              style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer', fontSize: 18 }}>
              <i className="fas fa-times"></i>
            </button>
          )}
        </div>
        <div style={{ padding: 16, display: 'flex', flexDirection: 'column', gap: 10 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>Tipo Identificación:</label>
            <select value={tipoIdentificacion}
              onChange={handleTipoChange}
              style={{ flex: 1, padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 4, fontSize: 12 }}>
              {TIPOS_IDENTIFICACION.map(t => (
                <option key={t.value} value={t.value}>{t.label}</option>
              ))}
            </select>
          </div>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>Identificación:</label>
              <input type="text" value={identificacion}
                onChange={handleIdentificacionChange}
                maxLength={getMaxLength()}
                style={{
                  flex: 1, padding: '6px 8px', borderRadius: 4, fontSize: 12,
                  border: validacionId
                    ? (validacionId.valido ? '2px solid #22c55e' : '2px solid #ef4444')
                    : '1px solid #cbd5e1',
                  outline: 'none',
                  background: validacionId && !validacionId.valido ? '#fef2f2' : 'white'
                }} />
            </div>
            {validacionId && (
              <div style={{
                fontSize: 10, fontWeight: 600, marginTop: 3, marginLeft: 128,
                color: validacionId.valido ? '#16a34a' : '#dc2626'
              }}>
                <i className={`fas ${validacionId.valido ? 'fa-check-circle' : 'fa-exclamation-circle'}`} style={{ marginRight: 4 }}></i>
                {validacionId.msg}
              </div>
            )}
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>Nombres:</label>
            <input type="text" value={nombres}
              onChange={e => setNombres(e.target.value)}
              style={{ flex: 1, padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 4, fontSize: 12 }} />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>Dirección:</label>
            <input type="text" value={direccion}
              onChange={e => setDireccion(e.target.value)}
              style={{ flex: 1, padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 4, fontSize: 12 }} />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>Celular:</label>
            <input type="text" value={celular}
              onChange={e => setCelular(e.target.value.replace(/\D/g, ''))}
              maxLength={10}
              placeholder="Solo números"
              style={{ flex: 1, padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 4, fontSize: 12 }} />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>Correo:</label>
            <input type="email" value={correo}
              onChange={e => setCorreo(e.target.value)}
              style={{ flex: 1, padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 4, fontSize: 12 }} />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <label style={{ fontSize: 12, fontWeight: 600, width: 120 }}>F. Nacimiento:</label>
            <input type="date" value={fechaNacimiento}
              onChange={e => setFechaNacimiento(e.target.value)}
              style={{ flex: 1, padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 4, fontSize: 12 }} />
          </div>
        </div>
        <div style={{ padding: '12px 16px', borderTop: '1px solid #e2e8f0', display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
          {!isForcedEdit && (
            <button onClick={() => { resetForm(); onClose(); }}
              style={{ padding: '8px 16px', border: '1px solid #cbd5e1', borderRadius: 4, background: 'white', cursor: 'pointer', fontSize: 12 }}>
              Cancelar
            </button>
          )}
          <button onClick={handleGuardar} disabled={saving}
            style={{
              padding: '8px 16px', border: 'none', borderRadius: 4,
              background: '#0a365d', color: 'white', cursor: 'pointer',
              fontSize: 12, fontWeight: 'bold', opacity: saving ? 0.7 : 1
            }}>
            {saving ? 'Guardando...' : (esEdicion ? 'Actualizar Cliente' : 'Guardar Cliente')}
          </button>
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect, useRef } from 'react';
import { api, clienteApi } from '../../../config/axios';
import toast from 'react-hot-toast';

const TARIFAS = [
  { value: 'Normal', text: 'Normal' },
  { value: '50% 3ra Edad', text: '50% 3ra Edad' },
  { value: '50% Menor', text: '50% Menor' },
  { value: '50% Discap.', text: '50% Discap.' },
  { value: '50% Estudiante', text: '50% Estudiante' },
  { value: 'Gratis Cortesía', text: 'Gratis Cortesía' },
];

export const PasajerosGrid = ({ pasajeros, onChange, destinosViaje, precioUnitario, onTotalesChange }) => {
  const [editingField, setEditingField] = useState(null);

  const handleInputChange = (asiento, campo, valor) => {
    const nuevos = pasajeros.map(p => {
      if (p.asiento === asiento) {
        const updated = { ...p, [campo]: valor };

        // Si cambia destino, usar el valor del nuevo destino
        if (campo === 'id_destino') {
          const destino = destinosViaje?.find(d => String(d.id_sub_rutas) === String(valor));
          const nuevoPrecioBase = destino ? parseFloat(destino.valor_sub_rutas || 0) : (parseFloat(p.valor || 0) + parseFloat(p.descuento || 0));
          const pActualizado = recalcularValor(updated, nuevoPrecioBase);
          recalcularTotal([...pasajeros.map(pp => pp.asiento === asiento ? pActualizado : pp)]);
          return pActualizado;
        }

        // Si cambia tarifa, recalcular valor con el precio base actual
        if (campo === 'tarifa') {
          const precioBase = parseFloat(p.valor || 0) + parseFloat(p.descuento || 0);
          const pActualizado = recalcularValor(updated, precioBase);
          // Propagar cambio de total
          recalcularTotal([...pasajeros.map(pp => pp.asiento === asiento ? pActualizado : pp)]);
          return pActualizado;
        }
        return updated;
      }
      return p;
    });
    onChange(nuevos);
  };

  const recalcularValor = (pasajero, precio) => {
    const p = precio || 0;
    let valorFinal = 0;
    let descuento = 0;

    switch (pasajero.tarifa) {
      case 'Normal':
        valorFinal = p;
        descuento = 0;
        break;
      case '50% 3ra Edad':
      case '50% Menor':
      case '50% Discap.':
      case '50% Estudiante':
        valorFinal = p / 2;
        descuento = p / 2;
        break;
      case 'Gratis Cortesía':
        valorFinal = 0;
        descuento = p;
        break;
      default:
        valorFinal = p;
        descuento = 0;
    }

    return { ...pasajero, valor: valorFinal, descuento };
  };

  const recalcularTotal = (lista) => {
    const total = lista.reduce((sum, p) => sum + parseFloat(p.valor || 0), 0);
    if (onTotalesChange) onTotalesChange(total);
  };

  const handleEliminar = (asiento) => {
    const nuevos = pasajeros.filter(p => p.asiento !== asiento);
    onChange(nuevos);
    recalcularTotal(nuevos);
  };

  const ultimaBusquedaRef = useRef({});

  const buscarClientePorCI = async (asiento, cedula) => {
    if (!cedula || cedula.length < 10) return;
    // Evitar búsqueda duplicada para el mismo asiento/misma cédula (solo si ya fue exitosa)
    const key = `${asiento}-${cedula}`;
    if (ultimaBusquedaRef.current[key]) return;

    const toastId = toast.loading(`Buscando cliente para asiento ${asiento}...`);
    const aplicarClienteEncontrado = (c) => {
      const nuevos = pasajeros.map(p => {
        if (p.asiento === asiento) {
          return { ...p, cedula: c.identificacion_cliente, nombres: c.nombre_cliente };
        }
        return p;
      });
      onChange(nuevos);
      // Marcar como exitosa para evitar re-búsquedas innecesarias
      ultimaBusquedaRef.current[key] = true;
    };

    try {
      const res = await clienteApi.get('/cliente/clientebusquedaIdentificacion', {
        params: { identificacion_busqueda: cedula }
      });
      if (res.data?.success && res.data?.total > 0) {
        const c = res.data.data[0];
        aplicarClienteEncontrado(c);
        toast.success(`Cliente encontrado: ${c.nombre_cliente}`, { id: toastId });
        return;
      }
      // Fallback: intentar con backend local
      try {
        const res2 = await api.get('/cliente/clientebusquedaIdentificacion', {
          params: { identificacion_busqueda: cedula }
        });
        if (res2.data?.success && res2.data?.total > 0) {
          const c = res2.data.data[0];
          aplicarClienteEncontrado(c);
          toast.success(`Cliente encontrado: ${c.nombre_cliente} (local)`, { id: toastId });
          return;
        }
        toast.error('Cliente no encontrado con esa identificación', { id: toastId });
      } catch {
        toast.error('Error al buscar cliente - servidor no disponible', { id: toastId });
      }
    } catch {
      // Fallback: intentar con backend local
      try {
        const res2 = await api.get('/cliente/clientebusquedaIdentificacion', {
          params: { identificacion_busqueda: cedula }
        });
        if (res2.data?.success && res2.data?.total > 0) {
          const c = res2.data.data[0];
          aplicarClienteEncontrado(c);
          toast.success(`Cliente encontrado: ${c.nombre_cliente} (local)`, { id: toastId });
          return;
        }
        toast.error('Cliente no encontrado', { id: toastId });
      } catch {
        toast.error('Error al buscar cliente - servidor no disponible', { id: toastId });
      }
    }
  };

  const handleBuscarCliente = (asiento, cedula) => {
    buscarClientePorCI(asiento, cedula);
  };

  // Recalcular total cuando cambian los pasajeros (nuevo asiento, eliminar, etc.)
  useEffect(() => {
    if (pasajeros.length > 0) {
      recalcularTotal(pasajeros);
    } else {
      if (onTotalesChange) onTotalesChange(0);
    }
  }, [pasajeros]); // eslint-disable-line react-hooks/exhaustive-deps



  return (
    <div className="table-responsive" style={{ width: '100%' }}>
      <table className="guias-table" style={{ border: '1px solid #cbd5e1', fontSize: '12px', width: '100%', tableLayout: 'auto' }}>
        <thead>
          <tr>
            <th style={{ width: '12%', minWidth: '90px' }}>Destino</th>
            <th style={{ width: '7%', minWidth: '50px' }}>Asiento</th>
            <th style={{ width: '15%', minWidth: '100px' }}>Cédula / RUC</th>
            <th style={{ width: '22%', minWidth: '120px' }}>Nombre</th>
            <th style={{ width: '10%', minWidth: '70px' }} className="text-right">Valor</th>
            <th style={{ width: '10%', minWidth: '70px' }} className="text-right">Dcto</th>
            <th style={{ width: '14%', minWidth: '100px' }}>Tarifa</th>
            <th style={{ width: '5%', minWidth: '30px' }}></th>
          </tr>
        </thead>
        <tbody>
          {pasajeros.length === 0 ? (
            <tr>
              <td colSpan="8" className="text-center" style={{ padding: '30px', color: '#94a3b8' }}>
                <i className="fas fa-hand-pointer" style={{ fontSize: '24px', marginBottom: '10px', display: 'block' }}></i>
                Seleccione asientos en el visualizador del bus.
              </td>
            </tr>
          ) : (
            pasajeros.map(p => (
              <tr key={p.asiento}>
                <td className="text-center">
                  <select
                    value={p.id_destino || ''}
                    onChange={e => handleInputChange(p.asiento, 'id_destino', e.target.value)}
                    style={{ width: '100%', padding: '4px', border: '1px solid #cbd5e1', borderRadius: '4px', fontSize: '11px' }}
                  >
                    <option value="">-</option>
                    {destinosViaje && destinosViaje.map(d => (
                      <option key={d.id_sub_rutas} value={d.id_sub_rutas}>{d.nombre_sub_rutas}</option>
                    ))}
                  </select>
                </td>
                <td className="text-center font-mono font-bold" style={{ color: '#3b82f6' }}>
                  {p.asiento}
                </td>
                <td>
                  <input
                    type="text"
                    value={p.cedula || ''}
                    onChange={e => handleInputChange(p.asiento, 'cedula', e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handleBuscarCliente(p.asiento, p.cedula)}
                    onBlur={e => {
                      const val = e.target.value;
                      if (val && val.length >= 10) {
                        handleBuscarCliente(p.asiento, val);
                      }
                    }}
                    placeholder="C.I."
                    style={{ width: '100%', padding: '4px 6px', border: '1px solid #cbd5e1', borderRadius: '4px', fontSize: '11px' }}
                  />
                </td>
                <td>
                  <input
                    type="text"
                    value={p.nombres || ''}
                    onChange={e => handleInputChange(p.asiento, 'nombres', e.target.value)}
                    placeholder="Nombre completo"
                    style={{ width: '100%', padding: '4px 6px', border: '1px solid #cbd5e1', borderRadius: '4px', fontSize: '11px' }}
                  />
                </td>
                <td className="text-right font-mono" style={{ fontWeight: 600, color: '#059669' }}>
                  ${parseFloat(p.valor || 0).toFixed(2)}
                </td>
                <td className="text-right font-mono" style={{ fontWeight: 600, color: '#dc2626' }}>
                  {parseFloat(p.descuento || 0) > 0 ? `-$${parseFloat(p.descuento).toFixed(2)}` : '-'}
                </td>
                <td>
                  <select
                    value={p.tarifa || 'Normal'}
                    onChange={e => handleInputChange(p.asiento, 'tarifa', e.target.value)}
                    style={{ width: '100%', padding: '4px', border: '1px solid #cbd5e1', borderRadius: '4px', fontSize: '11px' }}
                  >
                    {TARIFAS.map(t => (
                      <option key={t.value} value={t.value}>{t.text}</option>
                    ))}
                  </select>
                </td>
                <td className="text-center">
                  <button
                    onClick={() => handleEliminar(p.asiento)}
                    style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '2px' }}
                    title="Eliminar"
                  >
                    <i className="fas fa-minus-circle"></i>
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

