import React, { useState, useEffect } from 'react';
import CantonList from './components/CantonList';
import CantonSearchBar from './components/CantonSearchBar';
import NewCantonForm from './components/NewCantonForm';
import Modal from '../../components/common/Modal';
import Swal from 'sweetalert2';
import { getCantones, createCanton, updateCanton, deleteCanton } from '../../services/canton.service';

const CantonPage = () => {
  const [cantones, setCantones] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [editingCanton, setEditingCanton] = useState(null);
  const [filters, setFilters] = useState({ nombre: '', id_fkprovincia: '' });
  const [pagination, setPagination] = useState({ currentPage: 1, totalPages: 1, pageSize: 25 });

  const fetchCantones = async (currentFilters, currentPage) => {
    setLoading(true);
    try {
      const params = {
        nombre: currentFilters.nombre,
        id_fkprovincia: currentFilters.id_fkprovincia,
        page: currentPage,
        limit: pagination.pageSize,
      };
      const response = await getCantones(params);
      setCantones(response.data);
      setPagination((prev) => ({ ...prev, totalPages: Math.ceil(response.total / prev.pageSize) }));
    } catch (err) {
      setError(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCantones(filters, pagination.currentPage);
  }, [filters, pagination.currentPage]);

  const handleSearch = (newFilters) => {
    setFilters(newFilters);
    setPagination((prev) => ({ ...prev, currentPage: 1 }));
  };

  const handleRefresh = () => {
    setFilters({ nombre: '', id_fkprovincia: '' });
    setPagination({ currentPage: 1, totalPages: 1, pageSize: 25 });
  };

  const handlePageChange = (newPage) => {
    if (newPage > 0 && newPage <= pagination.totalPages) {
      setPagination((prev) => ({ ...prev, currentPage: newPage }));
    }
  };

  const handleNewCantonClick = () => {
    setEditingCanton(null);
    setShowModal(true);
  };

  const handleEditCanton = (canton) => {
    setEditingCanton(canton);
    setShowModal(true);
  };

  const handleDeleteCanton = async (id) => {
    const result = await Swal.fire({
      title: 'Confirmar',
      text: '¿Está seguro de que desea eliminar este cantón?',
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: 'Sí, eliminar',
      cancelButtonText: 'Cancelar'
    });
    if (result.isConfirmed) {
      try {
        await deleteCanton(id);
        fetchCantones(filters, pagination.currentPage);
      } catch (err) {
        setError(err);
      }
    }
  };

  const handleSubmitForm = async (formData) => {
    try {
      if (formData.id) {
        await updateCanton(formData);
      } else {
        await createCanton(formData);
      }
      setShowModal(false);
      fetchCantones(filters, pagination.currentPage);
    } catch (err) {
      setError(err);
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setEditingCanton(null);
  };

  if (loading) return <p>Cargando cantones...</p>;
  if (error) return <p>Error: {error.message}</p>;

  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold mb-4">Gestión de Cantones</h1>
      <button
        onClick={handleNewCantonClick}
        className="bg-green-500 hover:bg-green-700 text-white font-bold py-2 px-4 rounded mb-4"
      >
        Nuevo Cantón
      </button>
      <CantonSearchBar onSearch={handleSearch} onRefresh={handleRefresh} />
      <CantonList
        cantones={cantones}
        onEdit={handleEditCanton}
        onDelete={handleDeleteCanton}
        onPageChange={handlePageChange}
        currentPage={pagination.currentPage}
        totalPages={pagination.totalPages}
      />

      {showModal && (
        <Modal title={editingCanton ? 'Editar Cantón' : 'Nuevo Cantón'} onClose={handleCloseModal}>
          <NewCantonForm
            initialData={editingCanton}
            onSubmit={handleSubmitForm}
            onCancel={handleCloseModal}
          />
        </Modal>
      )}
    </div>
  );
};

export default CantonPage;

import React, { useState, useEffect } from 'react';
import { useForm, Controller } from 'react-hook-form';
import { api } from '../../../config/axios';
import ProvinciaSelect from '../../../components/common/ProvinciaSelect';
import toast from 'react-hot-toast';

const NewCantonForm = ({ initialData, onSubmit, onCancel }) => {
  const isEditing = !!initialData;
  const [loading, setLoading] = useState(false);

  const { register, handleSubmit, control, formState: { errors } } = useForm({
    defaultValues: {
      id: initialData?.id_canton || '',
      nombre_canton: initialData?.nombre_canton || '',
      id_fkprovincia: initialData?.id_fkprovincia || '',
    }
  });

  const onFormSubmit = async (data) => {
    console.log('[NewCantonForm] onFormSubmit called with data:', data);
    if (!data.id_fkprovincia) {
      toast.error('Debe seleccionar una provincia');
      return;
    }
    setLoading(true);
    try {
      const payload = {
        id: isEditing ? initialData.id_canton : null,
        nombre_canton: data.nombre_canton.toUpperCase(),
        id_fkprovincia: data.id_fkprovincia,
      };
      console.log('[NewCantonForm] Sending payload:', payload);
      const res = await api.post('/canton/cantonInsertarActualizar', payload);
      console.log('[NewCantonForm] Response:', res.data);
      if (res.data.success) {
        toast.success(isEditing ? 'Cantón actualizado correctamente' : 'Cantón creado correctamente');
        onSubmit(data);
      } else {
        toast.error(res.data.mensaje || 'Error al guardar');
      }
    } catch (err) {
      console.error('[NewCantonForm] Error guardando cantón:', err);
      toast.error('Error al guardar el cantón: ' + (err.response?.data?.mensaje || err.message));
    } finally {
      setLoading(false);
    }
  };

  const inputClass = "w-full h-9 px-3 text-sm border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-400 transition-all bg-white text-slate-800";
  const labelClass = "block text-xs font-bold text-slate-600 uppercase tracking-wider mb-1.5";
  const errorClass = "text-rose-500 text-xs mt-1 flex items-center gap-1";

  return (
    <form onSubmit={handleSubmit(onFormSubmit)} className="space-y-5">
      <input type="hidden" {...register('id')} />
      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">

        {/* Provincia */}
        <div>
          <label className={labelClass}>Provincia <span className="text-rose-500">*</span></label>
          <Controller
            name="id_fkprovincia"
            control={control}
            rules={{ required: 'La provincia es requerida' }}
            render={({ field }) => (
              <ProvinciaSelect
                name="id_fkprovincia"
                value={field.value}
                onChange={(e) => field.onChange(e.target.value)}
                className={inputClass}
                label={null}
                hideWrapper={true}
              />
            )}
          />
          {errors.id_fkprovincia && <p className={errorClass}><i className="fas fa-exclamation-circle" />{errors.id_fkprovincia.message}</p>}
        </div>

        {/* Nombre del Cantón */}
        <div>
          <label className={labelClass}>Nombre del Cantón <span className="text-rose-500">*</span></label>
          <input
            type="text"
            {...register('nombre_canton', { required: 'El nombre es requerido' })}
            className={inputClass}
            placeholder="Ej: Ambato"
          />
          {errors.nombre_canton && <p className={errorClass}><i className="fas fa-exclamation-circle" />{errors.nombre_canton.message}</p>}
        </div>

      </div>

      {/* Botones */}
      <div className="flex justify-end gap-3 pt-5 border-t border-slate-100">
        <button
          type="button"
          onClick={onCancel}
          className="px-5 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 text-sm font-bold transition-all"
        >
          <i className="fas fa-times mr-2" />Cancelar
        </button>
        <button
          type="submit"
          disabled={loading}
          className="px-5 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg text-sm font-bold transition-all shadow-sm disabled:opacity-70 flex items-center gap-2"
        >
          {loading
            ? <><i className="fas fa-spinner fa-spin" />Guardando...</>
            : <><i className="fas fa-save" />Guardar</>
          }
        </button>
      </div>
    </form>
  );
};

export default NewCantonForm;

