        <button onClick={() => onAgregarGuiaClick(despacho)} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg transition-all" title="Agregar Guía">
          <i className="fas fa-plus-circle text-sm"></i>
        </button>
      </div>
