import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { api } from '../../../config/axios';
import toast from 'react-hot-toast';
import CompaniaSelect from '../../../components/common/CompaniaSelect';

const NewDestinoForm = ({ initialData, onSubmit, onCancel }) => {
  const isEditing = !!initialData;
  const [loading, setLoading] = useState(false);
  const { register, handleSubmit, formState: { errors }, reset, setValue, watch } = useForm();

  const watchLugar = watch('lugar_destino');
  const watchCompania = watch('idfk_compania_asociada_destino');

  // ── Estado para Provincia → Ciudades ─────────────────
  const [provincias, setProvincias] = useState([]);
  const [cantones, setCantones] = useState([]);
  const [selectedProvincia, setSelectedProvincia] = useState('');
  const [loadingCantones, setLoadingCantones] = useState(false);

  // Cargar provincias al montar
  useEffect(() => {
    const fetchProvincias = async () => {
      try {
        const res = await api.get('/locacion/seleccionarProvincia');
        const data = res?.data?.data || res?.data || [];
        setProvincias(data);
      } catch (e) {
        console.error('Error cargando provincias:', e);
      }
    };
    fetchProvincias();
  }, []);

  // Cargar cantones cuando cambia la provincia
  useEffect(() => {
    if (!selectedProvincia) {
      setCantones([]);
      setValue('lugar_destino', '');
      return;
    }
    const fetchCantones = async () => {
      setLoadingCantones(true);
      try {
        const res = await api.get('/canton/cantonSeleccionarCombo', {
          params: { id_fkprovincia: selectedProvincia }
        });
        const data = res?.data?.data || res?.data || [];
        // Ordenar alfabéticamente por nombre
        const ordenados = [...data].sort((a, b) => {
          const nombreA = (a.nombre_canton || a.nombre || '').toLowerCase();
          const nombreB = (b.nombre_canton || b.nombre || '').toLowerCase();
          return nombreA.localeCompare(nombreB);
        });
        setCantones(ordenados);
      } catch (e) {
        console.error('Error cargando cantones:', e);
        setCantones([]);
      } finally {
        setLoadingCantones(false);
      }
    };
    fetchCantones();
  }, [selectedProvincia, setValue]);

  // Al editar, si ya hay lugar_destino, buscar su provincia para auto-seleccionarla
  useEffect(() => {
    if (initialData?.lugar_destino && provincias.length > 0 && !selectedProvincia) {
      api.get('/locacion/seleccionarCiudad').then(r => {
        const todas = r?.data?.data || [];
        const targetValue = String(initialData.lugar_destino).toLowerCase();
        const match = todas.find(c => 
          String(c.id_canton) === targetValue || 
          (c.nombre_canton || '').toLowerCase() === targetValue
        );
        if (match && match.id_fkprovincia) {
          setSelectedProvincia(match.id_fkprovincia);
          // Asegurar que el form tenga el valor con la capitalización exacta que vendrá en el combo
          setValue('lugar_destino', match.nombre_canton || match.nombre || match.label);
        } else {
          setCantones(todas);
        }
      }).catch(() => {});
    }
  }, [initialData, provincias, selectedProvincia]);

  useEffect(() => {
    if (initialData) {
      reset({
        id: initialData.id_destino || '',
        nombre_destino: initialData.nombre_destino || '',
        lugar_destino: initialData.lugar_destino || '',
        idfk_compania_asociada_destino: initialData.idfk_compania_asociada_destino || '',
        contacto: initialData.contacto || initialData.numero_contacto || '',
        estado_destino: initialData.estado_destino == 1 || initialData.estado_destino === '1'
      });
    } else {
      reset({
        id: '',
        nombre_destino: '',
        lugar_destino: '',
        idfk_compania_asociada_destino: '',
        contacto: '',
        estado_destino: true
      });
    }
  }, [initialData, reset]);

  const handleValidSubmit = async (data) => {
    if (!data.lugar_destino || !data.idfk_compania_asociada_destino) return;
    setLoading(true);
    try {
      const payload = {
        ...data,
        estado_destino: data.estado_destino ? '1' : '0',
      };
      await api.post('/destino/destinoinsertarActualizar', payload);
      toast.success(isEditing ? 'Destino actualizado correctamente' : 'Destino creado correctamente');
      onSubmit();
    } catch (err) {
      toast.error('Error al guardar. ' + (err.response?.data?.mensaje || err.message));
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleValidSubmit)} className="space-y-6">
      <div className="bg-white rounded-xl border border-slate-200 p-6 space-y-4">
        <input type="hidden" {...register('id')} />

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

          {/* Nombre/Dirección */}
          <div className="md:col-span-2">
            <label className="block text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">
              Dirección / Nombre del Destino <span className="text-rose-500">*</span>
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <i className="fas fa-map-marker-alt text-slate-400"></i>
              </div>
              <input
                type="text"
                {...register('nombre_destino', { required: 'La dirección es obligatoria' })}
                className={`w-full pl-10 pr-4 py-2 bg-slate-50 border rounded-lg text-sm focus:ring-2 focus:outline-none transition-all ${
                  errors.nombre_destino ? 'border-rose-300 focus:ring-rose-200' : 'border-slate-200 focus:ring-blue-100 focus:border-blue-400'
                }`}
                placeholder="Ej: Terminal Terrestre Guayaquil"
                autoFocus
              />
            </div>
            {errors.nombre_destino && <p className="mt-1 text-xs text-rose-500 font-medium">{errors.nombre_destino.message}</p>}
          </div>

          {/* Provincia */}
          <div>
            <label className="block text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">
              Provincia <span className="text-rose-500">*</span>
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <i className="fas fa-map text-slate-400"></i>
              </div>
              <select
                value={selectedProvincia}
                onChange={(e) => setSelectedProvincia(e.target.value)}
                className={`w-full pl-10 pr-4 py-2 bg-slate-50 border rounded-lg text-sm focus:ring-2 focus:outline-none transition-all ${
                  errors.lugar_destino ? 'border-rose-300 focus:ring-rose-200' : 'border-slate-200 focus:ring-blue-100 focus:border-blue-400'
                }`}
              >
                <option value="">Seleccione una provincia...</option>
                {provincias.map((p) => (
                  <option key={p.id_provincia || p.id || p.value} value={p.id_provincia || p.id || p.value}>
                    {p.nombre_provincia || p.nombre || p.label}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {/* Ciudad */}
          <div>
            <label className="block text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">
              Ciudad <span className="text-rose-500">*</span>
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <i className="fas fa-city text-slate-400"></i>
              </div>
              <select
                value={watchLugar || ''}
                onChange={(e) => setValue('lugar_destino', e.target.value)}
                disabled={!selectedProvincia || loadingCantones}
                className={`w-full pl-10 pr-4 py-2 border rounded-lg text-sm focus:ring-2 focus:outline-none transition-all ${
                  !selectedProvincia ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-slate-50'
                } ${
                  errors.lugar_destino ? 'border-rose-300 focus:ring-rose-200' : 'border-slate-200 focus:ring-blue-100 focus:border-blue-400'
                }`}
              >
                <option value="">
                  {loadingCantones
                    ? 'Cargando ciudades...'
                    : selectedProvincia
                      ? 'Seleccione una ciudad...'
                      : 'Primero seleccione una provincia'
                  }
                </option>
                {cantones.map((c) => (
                  <option key={c.id_canton || c.id || c.value} value={c.nombre_canton || c.nombre || c.label}>
                    {c.nombre_canton || c.nombre || c.label}
                  </option>
                ))}
              </select>
            </div>
            {(!watchLugar && errors.lugar_destino) && <p className="mt-1 text-xs text-rose-500 font-medium">Debe seleccionar una ciudad.</p>}
          </div>

          {/* Compañía Asociada */}
          <div>
            <label className="block text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">
              Compañía <span className="text-rose-500">*</span>
            </label>
            <CompaniaSelect
              value={watchCompania}
              onChange={(e) => setValue('idfk_compania_asociada_destino', e.target.value)}
              name="idfk_compania_asociada_destino"
              label=""
            />
            {(!watchCompania && errors.idfk_compania_asociada_destino) && <p className="mt-1 text-xs text-rose-500 font-medium">Debe seleccionar una compañía.</p>}
          </div>

          {/* Contacto */}
          <div>
            <label className="block text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">
              Contacto (Teléfono) <span className="text-rose-500">*</span>
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <i className="fas fa-phone-alt text-slate-400"></i>
              </div>
              <input
                type="text"
                maxLength="15"
                {...register('contacto', { 
                  required: 'El teléfono es obligatorio',
                  pattern: { value: /^[0-9]+$/, message: 'Debe contener solo números' },
                  maxLength: { value: 15, message: 'Máximo 15 dígitos' }
                })}
                className={`w-full pl-10 pr-4 py-2 bg-slate-50 border rounded-lg text-sm focus:ring-2 focus:outline-none transition-all ${
                  errors.contacto ? 'border-rose-300 focus:ring-rose-200' : 'border-slate-200 focus:ring-blue-100 focus:border-blue-400'
                }`}
                placeholder="Ej: 0987654321"
              />
            </div>
            {errors.contacto && <p className="mt-1 text-xs text-rose-500 font-medium">{errors.contacto.message}</p>}
          </div>

          {/* Estado (Switch) */}
          <div className="flex flex-col justify-center">
            <label className="block text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">Estado</label>
            <label className="relative inline-flex items-center cursor-pointer mt-1">
              <input 
                type="checkbox" 
                className="sr-only peer"
                {...register('estado_destino')}
              />
              <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-slate-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-emerald-500"></div>
              <span className="ml-3 text-sm font-semibold text-slate-700">Activo</span>
            </label>
          </div>

        </div>
      </div>

      {/* Botones de Acción */}
      <div className="flex items-center justify-end gap-3 pt-2">
        <button
          type="button"
          onClick={onCancel}
          className="px-5 py-2.5 text-sm font-bold text-slate-600 bg-white border border-slate-300 rounded-xl hover:bg-slate-50 hover:text-slate-800 transition-all shadow-sm flex items-center gap-2"
        >
          <i className="fas fa-times"></i>
          Cancelar
        </button>
        <button
          type="submit"
          disabled={loading}
          className="px-5 py-2.5 text-sm font-bold text-white bg-emerald-600 border border-emerald-700 rounded-xl hover:bg-emerald-700 shadow-sm shadow-emerald-600/20 transition-all flex items-center gap-2 disabled:opacity-60"
        >
          {loading ? <><i className="fas fa-spinner fa-spin"></i> Guardando...</> : <><i className="fas fa-save"></i> Guardar Destino</>}
        </button>
      </div>
    </form>
  );
};

export default NewDestinoForm;

import { useState, useEffect, useCallback } from 'react';
import toast from 'react-hot-toast';
import { CONFIG } from '../../config/env';
import { EntregaService } from '../../services/entrega.service';
import { CobrarEntregarModal } from './components/CobrarEntregarModal';
import { ConfirmarEntregaModal } from './components/ConfirmarEntregaModal';

const PAGE_SIZE = 25;

export const EntregasPage = ({ isNotaVenta = false }) => {
  // ─── Estado principal ──────────────────────────────────────
  const [guias, setGuias] = useState([]);
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);

  // ─── Filtros ───────────────────────────────────────────────
  const [filtros, setFiltros] = useState({
    cedula_remitente: '',
    cedula_destinatario: '',
    nombre_remitente: '',
    nombre_destinatario: '',
    mes: '',
    anio: '',
    fechaini: '',
    fechalast: '',
    numeroguia: '',
    estado: '0'
  });

  // ─── Modal state ───────────────────────────────────────────
  const [selectedGuia, setSelectedGuia] = useState(null);
  const [modalType, setModalType] = useState(null); // 'cobrar' | 'confirmar'

  // ─── Fetch data ────────────────────────────────────────────
  const cargarGuias = useCallback(async (pageNum = 1, filtrosActuales = null) => {
    setLoading(true);
    try {
      const f = filtrosActuales || filtros;
      const params = {
        rucremitente: f.cedula_remitente || '',
        rucreceptor: f.cedula_destinatario || '',
        nombreremitente: f.nombre_remitente || '',
        nombrereceptor: f.nombre_destinatario || '',
        fechaini: f.fechaini || '',
        fechalast: f.fechalast || '',
        mes: f.mes || '',
        anio: f.anio || '',
        estado: f.estado || '0',
        numeroguia: f.numeroguia || '',
        idusuario: '',
        page: pageNum,
        limit: PAGE_SIZE
      };
      const res = await EntregaService.listar(params, isNotaVenta);
      if (res?.success) {
        setGuias(res.data || []);
        setTotal(res.total || 0);
        setPage(pageNum);
      } else {
        setGuias([]);
        setTotal(0);
      }
    } catch (error) {
      console.error('Error cargando guías:', error);
      toast.error('Error al cargar guías');
      setGuias([]);
    } finally {
      setLoading(false);
    }
  }, [filtros]);

  useEffect(() => {
    cargarGuias(1);
  }, []);

  // ─── Handlers de filtros ───────────────────────────────────
  const handleFilterChange = (key, value) => {
    setFiltros(prev => ({ ...prev, [key]: value }));
  };

  const handleBuscar = () => {
    cargarGuias(1, filtros);
  };

  const handleRefrescar = () => {
    const limpio = {
      cedula_remitente: '', cedula_destinatario: '', nombre_remitente: '',
      nombre_destinatario: '', mes: '', anio: '', fechaini: '', fechalast: '',
      numeroguia: '', estado: '0'
    };
    setFiltros(limpio);
    cargarGuias(1, limpio);
  };

  const handlePageChange = (newPage) => {
    if (newPage < 1 || newPage > totalPages) return;
    cargarGuias(newPage);
  };

  // ─── Acción: Entregar Guía (flujo completo) ────────────────
  const handleEntregarGuia = async (guia) => {
    // Validaciones rápidas
    if (String(guia.estado_guias_entregadas) === '2') {
      toast.error('Esta guía ya se encuentra entregada');
      return;
    }
    if (String(guia.estado_oficina) === '1') {
      toast.error('Esta guía se encuentra en otra oficina, no puede entregar');
      return;
    }

    try {
      // 1. Verificar anulación
      const anulRes = await EntregaService.verificarAnulacion(guia.id_guia, isNotaVenta);
      const msg = anulRes?.message;
      if (msg === 2) { toast.error('La guía se encuentra anulada'); return; }
      if (msg === 3) { toast.error('La guía está pendiente de anulación'); return; }

      // 2. Verificar factura autorizada
      const factRes = await EntregaService.autorizadoFacturaPorGuia(guia.id_guia);
      if (!factRes?.data || factRes.data.length === 0) {
        toast.error('Esta guía no tiene una factura asociada');
        return;
      }
      const factData = factRes.data[0];
      const totalFactura = parseFloat(factData.total_factura || 0);

      // 3. Verificar suma ya cobrada
      let cobrado = 0;
      try {
        const sumRes = await EntregaService.facturaidguicobradasuma(guia.id_guia);
        // El backend devuelve { success: true, data: [{ total_factura: X }] }
        // o también puede devolver { success: true, data: X } (número directo)
        if (sumRes?.data) {
          if (Array.isArray(sumRes.data)) {
            cobrado = parseFloat(sumRes.data[0]?.total_factura || 0);
          } else if (typeof sumRes.data === 'object') {
            cobrado = parseFloat(sumRes.data.total_factura || 0);
          } else {
            cobrado = parseFloat(sumRes.data || 0);
          }
        }
      } catch (e) {
        console.warn('Error obteniendo suma cobrada:', e);
      }

      const pendiente = totalFactura - cobrado;

      if (pendiente <= 0) {
        // No hay cobro pendiente → entrega simple
        setSelectedGuia(guia);
        setModalType('confirmar');
      } else {
        // Hay cobro pendiente → validar caja
        const cajaRes = await EntregaService.validarCaja();
        if (cajaRes?.message === 1 || cajaRes?.success) {
          setSelectedGuia(guia);
          setModalType('cobrar');
        } else {
          toast.error('No hay una caja aperturada. Debe aperturar una caja primero.');
        }
      }
    } catch (err) {
      console.error('Error al verificar guía:', err);
      toast.error('Error al verificar la guía');
    }
  };

  // ─── Acción: PDF ───────────────────────────────────────────
  const handlePdf = async (guia) => {
    try {
      const userRes = await EntregaService.buscarUsuario();
      if (!userRes?.success) {
        toast.error('No se pudo obtener información del usuario');
        return;
      }
      const idUsuario = userRes.data.id_usuario;

      const pdfRes = await EntregaService.generarPdfEntrega(guia.id_guia, idUsuario, isNotaVenta);
      if (pdfRes?.success && pdfRes?.ruta) {
        const url = `${CONFIG.PHP_URL}/tmp/${pdfRes.ruta}`;
        window.open(url, 'PDF_Entrega', 'width=800,height=600');
      } else {
        toast.error('Error al generar PDF');
      }
    } catch (err) {
      console.error('Error PDF:', err);
      toast.error('Error al generar PDF');
    }
  };

  const handleModalSuccess = () => {
    cargarGuias(page);
  };

  // ─── Paginación ────────────────────────────────────────────
  const totalPages = Math.ceil(total / PAGE_SIZE);

  // ─── Render helpers ────────────────────────────────────────
  const formatNumeroGuia = (numero) => {
    if (!numero) return '';
    const s = String(numero);
    if (s.length >= 10) {
      return `${s.slice(0, 3)}-${s.slice(3, 6)}-${s.slice(6)}`;
    }
    return s;
  };

  const renderClienteRemitente = (g) => (
    <div className="text-[11px] leading-tight">
      <div className="text-slate-500"><b>RUC:</b> {g.cedula_cliente_remitente || '-'}</div>
      <div className="text-slate-700"><b>Razón:</b> {g.nombre_cliente_remitente || '-'}</div>
    </div>
  );

  const renderClienteDestinatario = (g) => (
    <div className="text-[11px] leading-tight">
      <div className="text-slate-500"><b>RUC:</b> {g.cedula_cliente_receptor || '-'}</div>
      <div className="text-slate-700"><b>Razón:</b> {g.nombre_cliente_receptor || '-'}</div>
    </div>
  );

  const renderEstadoOficina = (g) => {
    const val = String(g.estado_oficina);
    if (val === '1') return <i className="fas fa-map-marker-alt text-red-500" title="ESTA EN OTRA OFICINA"></i>;
    if (val === '0') return <i className="fas fa-map-marker-alt text-green-500" title="ESTA EN ESTA OFICINA"></i>;
    if (val === '2') return <i className="fas fa-map-marker-alt text-orange-500" title="ANTIGUA"></i>;
    return null;
  };

  const renderEstadoEntrega = (g) => {
    if (String(g.estado_guias_entregadas) === '2')
      return <span className="bg-green-100 text-green-800 text-[10px] font-bold px-2 py-0.5 rounded-full">ENTREGADO</span>;
    return <span className="bg-yellow-100 text-yellow-800 text-[10px] font-bold px-2 py-0.5 rounded-full">PENDIENTE</span>;
  };

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-6">
      {/* ─── TITLE ─── */}
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-black text-slate-800 tracking-tight flex items-center gap-3">
          <i className="fas fa-hand-holding-usd text-green-500"></i>
          {isNotaVenta ? 'ENTREGAS DE NOTAS DE VENTA' : 'GUIAS ENTREGADAS'}
          <span className="text-sm font-normal text-slate-400 bg-slate-100 px-3 py-1 rounded-full">
            {total} registro{total !== 1 ? 's' : ''}
          </span>
        </h1>
      </div>

      {/* ─── FILTROS ─── */}
      <div className="bg-white border border-slate-200 rounded-xl shadow-sm">
        <div className="px-5 py-3 border-b border-slate-100">
          <h3 className="text-sm font-bold text-slate-600 uppercase tracking-wider flex items-center gap-2">
            <i className="fas fa-search text-blue-500 text-xs"></i>
            Búsqueda de Entregados
          </h3>
        </div>
        <div className="p-5">
          <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Ced. Remitente</label>
              <input
                type="text" value={filtros.cedula_remitente}
                onChange={e => handleFilterChange('cedula_remitente', e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleBuscar()}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Ced. Destinatario</label>
              <input
                type="text" value={filtros.cedula_destinatario}
                onChange={e => handleFilterChange('cedula_destinatario', e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleBuscar()}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Remitente</label>
              <input
                type="text" value={filtros.nombre_remitente}
                onChange={e => handleFilterChange('nombre_remitente', e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleBuscar()}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Destinatario</label>
              <input
                type="text" value={filtros.nombre_destinatario}
                onChange={e => handleFilterChange('nombre_destinatario', e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleBuscar()}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Mes</label>
              <select
                value={filtros.mes}
                onChange={e => handleFilterChange('mes', e.target.value)}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm bg-white"
              >
                <option value="">Todos</option>
                {['01','02','03','04','05','06','07','08','09','10','11','12'].map(m => (
                  <option key={m} value={m}>{
                    ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'][parseInt(m)-1]
                  }</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Año</label>
              <select
                value={filtros.anio}
                onChange={e => handleFilterChange('anio', e.target.value)}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm bg-white"
              >
                <option value="">Todos</option>
                {[2019,2020,2021,2022,2023,2024,2025,2026].map(a => (
                  <option key={a} value={String(a)}>{a}</option>
                ))}
              </select>
