  const [descuentoTipo, setDescuentoTipo] = useState('0');

  // ── Valor Declarado (ExtJS: valor_declarado, porcentaje, valor_declarado_valor) ─
  const [valorDeclaradoActivo, setValorDeclaradoActivo] = useState(false);
