  const handleBuscarOtros = async () => {
    if (!otrosIdentidad || otrosIdentidad.length < 5) return;
    setOtrosLoading(true);
    try {
      const res = await GuiaService.buscarClientePorIdentificacion(otrosIdentidad);
      const data = res?.data;
      if (data && (data.id_cliente || data.id)) {
        setOtrosNombre(data.nombres || data.nombre || '');
        setOtrosTelefono(data.telefono || '');
        setOtrosCorreo(data.email || data.correo || '');
        setOtrosDireccion(data.direccion || '');

        if (!data.telefono || !(data.email || data.correo)) {
          toast.error('El cliente "Otros" no tiene correo o teléfono. Debe actualizarlos para continuar.');
        } else {
          toast.success('Cliente "Otros" encontrado');
        }
      } else {
        toast('Cliente no encontrado. Puede crear uno nuevo.');
      }
    } catch (e) {
      console.error('Error buscando otros:', e);
    } finally {
      setOtrosLoading(false);
    }
  };

  const handleLimpiarOtros = () => {
    setOtrosIdentidad('');
    setOtrosNombre('');
    setOtrosTelefono('');
    setOtrosCorreo('');
    setOtrosDireccion('');
  };

  // ── Handler Nuevo Cliente Otros ──────────────────────
  const handleNuevoClienteOtros = async () => {
    if (!otrosNewCliente.nombre_cliente || !otrosNewCliente.identificacion_cliente) {
      toast.error('Identificación y Nombre son obligatorios');
      return;
    }
    if (!/^\d+$/.test(otrosNewCliente.identificacion_cliente)) {
      toast.error('La identificación debe contener solo números');
      return;
    }
    if (otrosNewCliente.email_cliente && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(otrosNewCliente.email_cliente)) {
      toast.error('Formato de correo inválido');
      return;
    }
    setOtrosLoading(true);
    try {
      const { api } = await import('../../config/axios');
      await api.post('/cliente/ingresarActualizarCliente', {
        identificacion_cliente: otrosNewCliente.identificacion_cliente,
        tipo_identificacion_cliente: otrosNewCliente.tipo_identificacion_cliente,
        nombre_cliente: otrosNewCliente.nombre_cliente,
        direccion_cliente: otrosNewCliente.direccion_cliente,
        email_cliente: otrosNewCliente.email_cliente,
        telefono_cliente: otrosNewCliente.telefono_cliente
      });
      setOtrosIdentidad(otrosNewCliente.identificacion_cliente);
      setOtrosNombre(otrosNewCliente.nombre_cliente);
      setOtrosTelefono(otrosNewCliente.telefono_cliente);
      setOtrosCorreo(otrosNewCliente.email_cliente);
      setOtrosDireccion(otrosNewCliente.direccion_cliente);
      setOtrosShowCreate(false);
      toast.success('Cliente creado exitosamente');
    } catch (error) {
      console.error('Error creando cliente:', error);
      toast.error('Error al crear el cliente');
    } finally {
      setOtrosLoading(false);
    }
  };

  // ── Handler Convenio ────────────────────────────────
  const handleConvenioFound = (conv) => {
    setConvenio(conv);
  };

  // ── Autocompletar destinatario desde remitente ──────
  const handleDestinatarioAutoFill = (data) => {
    if (!data) return;
    const aux = data.id_cliente_receptor || data.id_cliente || data.cedula_cliente_receptor;
    if (!aux) return;
    const clienteData = {
      id_cliente: data.id_cliente_receptor || data.id_cliente || 0,
      cedula: data.cedula_cliente_receptor || data.identificacion_cliente || '',
      nombres: data.nombre_cliente_receptor || data.nombre_cliente || '',
      direccion: data.direccion_cliente_receptor || data.direccion_cliente || '',
      telefono: data.telefono_cliente_receptor || data.telefono_cliente || '',
      email: data.correo_cliente_receptor || data.email_cliente_receptor || data.email_cliente || '',
      telefono2: data.telefono2_cliente_receptor || data.telefono2 || ''
    };
    if (clienteData.nombres) {
      handleSetDestinatario(clienteData);
      toast.success('Destinatario autocompletado del último envío');
    }
  };

  // ── Wrappers para limpiar errores al cambiar campos ──
  const handleSetRemitente = (data) => { setRemitente(data); setFieldErrors(prev => ({ ...prev, remitente: undefined })); };
  const handleSetDestinatario = (data) => { setDestinatario(data); setFieldErrors(prev => ({ ...prev, destinatario: undefined })); };
  const handleSetCompania = (data) => { setCompania(data); setFieldErrors(prev => ({ ...prev, compania: undefined })); };
  const handleSetDestino = (id, texto, companyToSet = undefined) => { 
    setDestino(id); 
    setDestinoTexto(texto); 
    setFieldErrors(prev => ({ ...prev, destino: undefined })); 

    if (companyToSet !== undefined) {
      setCompania(companyToSet);
    } else {
      if (!id) {
        setCompania(null);
        return;
      }
      const matches = destinos.filter(d => String(d.id) === String(id));
      if (matches.length === 1) {
        if (matches[0].idfk_compania_asociada_destino) {
          setCompania({
            id: matches[0].idfk_compania_asociada_destino,
            id_compania_asociada: matches[0].idfk_compania_asociada_destino,
            nombre: matches[0].nombre_compania_asociada || '',
            ruc: matches[0].ruc_compania_asociada || matches[0].ruc_compania || matches[0].ruc || '',
            telefono: matches[0].numero_contacto || '',
            correo: ''
          });
        } else {
          setCompania(null);
        }
      } else if (matches.length > 1) {
        setMultiCompaniaOptions(matches);
        setShowMultiCompaniaModal(true);
      } else {
        setCompania(null);
      }
    }
  };
  const handleSetTipoEnvio = (val) => { setTipoEnvio(val); setFieldErrors(prev => ({ ...prev, tipoEnvio: undefined })); };
  const handleSetDetalles = (data) => { setDetalles(data); setFieldErrors(prev => ({ ...prev, detalles: undefined })); };

  const bandera = parseInt(facturarA) || 1; // 1=Remitente, 2=Destinatario, 3=Otros
  const canceladopor = pagadoPor === '1' ? 0 : 1; // 0=Remitente, 1=Destinatario

  // ── Handler Guardar ──────────────────────────────────
  const handleGuardar = async () => {
    // ── Validaciones completas con errores en rojo ANTES de confirmación ──
    const errors = {};
    if (!remitente || !remitente.cedula || !remitente.nombres) errors.remitente = true;
    if (!destinatario || !destinatario.cedula || !destinatario.nombres) errors.destinatario = true;
    if (!origen) errors.origen = true;
    if (!destino || !destinoTexto) errors.destino = true;
    if (!compania) errors.compania = true;
    if (!tipoEnvio) errors.tipoEnvio = true;
    if (facturarA === '3') {
      if (!otrosIdentidad || !otrosNombre || !otrosTelefono || !otrosCorreo) {
        errors.otros = true;
        toast.error('Debe completar el correo y teléfono en la sección "Otros"');
      }
    }
    if (detalles.length === 0) errors.detalles = true;
    const detalleInvalido = detalles.find(d => !d.contenido || (parseFloat(d.precioUnitario) <= 0 && parseFloat(d.subtotal) <= 0));
    if (detalleInvalido) errors.detalles = true;

    if (Object.keys(errors).length > 0) {
      setFieldErrors(errors);
      toast.error('Complete los campos marcados en rojo antes de guardar');
      return;
    }
    setFieldErrors({});

    // Validar caja aperturada (ExtJS: validarcaja antes de guardar)
    const cajaId = localCajaId || user?.id_caja_global || user?.id_caja;
    if (!cajaId) {
      toast.error('No hay una caja aperturada. Debe aperturar una caja primero.');
      return;
    }

    // Confirmación (ExtJS behavior)
    const confirmGuardar = await Swal.fire({ title: '¿Guardar guía?', text: '¿Está seguro de guardar la guía?', icon: 'question', showCancelButton: true, confirmButtonText: 'Sí, guardar', cancelButtonText: 'Cancelar' });
    if (!confirmGuardar.isConfirmed) return;

    // Calcular totales
    const totalSubtotal = detalles.reduce((sum, d) => sum + (d.subtotal || 0), 0);
    const totalDescuento = descuentoTipo === '2' ? totalSubtotal
      : descuentoTipo === '1' ? totalSubtotal * 0.5
        : detalles.reduce((sum, d) => sum + (d.descuento || 0), 0);
    const totalTarifa = detalles.reduce((sum, d) => sum + (d.tarifa || 0), 0);
    const subtotalConDescuento = totalSubtotal - totalDescuento;
    const totalIva = calcGuardarIva(detalles, descuentoTipo, tiposEnvio, cobrarIvaGuia);
    const totalGeneral = subtotalConDescuento + totalIva + totalTarifa;

    // ID del cliente según bandera (1=Remitente, 2=Destinatario, 3=Otros)
    const idClienteFactura = facturarA === '1'
      ? (remitente?.id_cliente || 0)
      : facturarA === '2'
        ? (destinatario?.id_cliente || 0)
        : 0;

    const parametros = {
      // Cabecera (coincide con ExtJS form field names)
      origen_guia: origen || user?.sucursal || user?.nombre_sucursal || user?.canton || '',
      origen: origen || user?.sucursal || user?.nombre_sucursal || user?.canton || '',
      destino_guia: destinoTexto || '',
      destino: destinoTexto || '',
      tipo_envio: parseInt(tipoEnvio) || null,
      id_fktipo_envio_guia: parseInt(tipoEnvio) || null,
      fechaguia: new Date().toISOString().split('T')[0],

      // Bandera (determina qué ID de cliente usar para factura: 1=Remitente, 2=Destinatario, 3=Otros)
      bandera: bandera,

      // Quién paga (0=Remitente, 1=Destinatario)
      canceladopor: canceladopor,

      // Caja global (del usuario autenticado o recién creada)
      id_caja_global: localCajaId || user?.id_caja_global || null,

      // Remitente (usa idclienterem como ExtJS)
      idclienterem: remitente.id_cliente || 0,
      id_remitente: remitente.id_cliente || null,
      cedula_remitente: remitente.cedula,
      nombre_remitente: remitente.nombres,
      direccion_remitente: remitente.direccion,
      direccionemisor: remitente.direccion,
      telefono_remitente: remitente.telefono,
      telefonoemisor: remitente.telefono,
      email_remitente: remitente.email,
      correoemisor: remitente.email,

      // Destinatario (usa idclienterec como ExtJS)
      idclienterec: destinatario.id_cliente || 0,
      id_destinatario: destinatario.id_cliente || null,
      cedula_destinatario: destinatario.cedula,
      cedula_receptor: destinatario.cedula,
      nombre_destinatario: destinatario.nombres,
      nombre_receptor: destinatario.nombres,
      direccion_destinatario: destinatario.direccion,
      direccionreceptor: destinatario.direccion,
      telefono_destinatario: destinatario.telefono,
      telefonoreceptor: destinatario.telefono,
      email_destinatario: destinatario.email,
      correorecptor: destinatario.email,
      telefono2_destinatario: destinatario.telefono2 || '',

      // A quién se factura
      facturar_a: parseInt(facturarA) || 1,
      a_quien_factura: parseInt(facturarA) || 1,

      // Compañía (ExtJS field name: idcompania)
      id_compania: compania?.id || compania?.id_compania || null,
      idcompania: compania?.id || compania?.id_compania || null,
      nombre_compania: compania?.nombre || '',
      ruc_compania: compania?.ruc || '',
      telefono_compania: compania?.telefono || '',

      // Otros (si facturar_a = 3)
      id_cliente_otros: 0,
      identidad_otros: facturarA === '3' ? otrosIdentidad : null,
      cedula_otros: facturarA === '3' ? otrosIdentidad : null,
      nombre_otros: facturarA === '3' ? otrosNombre : null,
      telefono_otros: facturarA === '3' ? otrosTelefono : null,
      email_otros: facturarA === '3' ? otrosCorreo : null,
      correo_otros: facturarA === '3' ? otrosCorreo : null,
      direccion_otros: facturarA === '3' ? otrosDireccion : null,

      // Descuento (tipodescuento como en ExtJS)
      descuento_tipo: descuentoTipo,
      tipodescuento: descuentoTipo,

      // Valor Declarado (ExtJS: porcentaje + valor_declarado_valor)
      porcentaje: valorDeclaradoActivo ? (parseFloat(sanitizeNum(valorDeclaradoPorcentaje)) || 0) : 0,
      valor_declarado: valorDeclaradoActivo
        ? (parseFloat(sanitizeNum(valorDeclaradoValor)) || (totalGeneral * (parseFloat(sanitizeNum(valorDeclaradoPorcentaje)) || 0) / 100) || 0)
        : 0,
      valor_declarado_valor: valorDeclaradoActivo ? (parseFloat(sanitizeNum(valorDeclaradoValor)) || 0) : 0,

      // Número Manual
      numero_manual: numeroManual ? 1 : 0,
      si_numero_manual: numeroManual ? 1 : 0,
      numero_manual_guia: numeroManual ? numeroManualGuia : null,

      // Detalles (array con nombres exactos que espera el backend = ExtJS)
      detalle_guia: detalles.map(d => ({
        id_fktipo_envio_detalle_guia: parseInt(tipoEnvio) || null,
        contenido_guia: d.contenido || '',
        peso_guia: d.peso || 0,
        costo_detalle_guia: d.precioUnitario || 0,
        documento_detalle_guia: '',
        tipo_descuento_detalle_guia: d.descuento || 0,
        tipo_iva_detalle_guia: d.iva || 0,
        total_detalle_guia: d.total || 0,
        subtotal_detalle_guia: d.subtotal || 0,
        cantidad_detalle_guia: d.cantidad || 1,
        total_tarifa_detalle_guia: d.tarifa || 0,
        id_guia: 0,
        sucursal: parseInt(user?.id_sucursal || user?.sucursal) || 0
      })),

      // Pagos (array con nombres exactos = ExtJS)
      comprobante_cobro: pagos.map(p => ({
        concepto_detalle: p.nombre || '',
        monto_comprobante: p.monto || 0,
        id_fkcliente: idClienteFactura,
        id_fkforma: p.id_forma_pago,
        observacion_comprobante: p.detalle || ''
      })),

      // Totales calculados
      subtotal_12: totalSubtotal,
      subtotal12: totalSubtotal,
      subtotal_0: 0,
      subtotal0: 0,
      subtotalguia: totalSubtotal,
      descuentoguia: totalDescuento,
      tarifa_factura: totalTarifa,
      valor_tarifa_adicional_guia: totalTarifa,
      impuestoiva: totalIva,
      total_factura: totalGeneral,

      // Valor total (display)
      valor_total: totalGeneral,
      total: totalGeneral,

      // Metadatos
      observacion: observacion,
      id_usuario: user?.id_usuario || user?.id,
      id_sucursal: user?.id_sucursal || user?.sucursal || null,
      sucursal: parseInt(user?.id_sucursal || user?.sucursal) || 0,
      estado: 'Pendiente'
    };

    // Si es edición, pasamos el id_guia
    if (isEditing) {
      parametros.id_guia = parseInt(idGuiaEdit);
    }

    setSaving(true);
    try {
      const result = isEditing
        ? await GuiaService.actualizarGuia(parametros)
        : await GuiaService.insertarGuia(parametros);

      if (result && result.success) {
        // Verificar tipo de respuesta (tipo 3 = no hay caja aperturada)
        if (result.tipo === 3) {
          toast.error(result.mensaje || 'No hay una caja aperturada');
          return;
        }
        const idGuia = result.message || result.id_guia;
        toast.success(`Guía guardada exitosamente. N° ${idGuia || ''}`);
        // Auto-imprimir / descargar PDF (como ExtJS: abrir PDF automáticamente)
        if (idGuia) {
          // Mostrar PDF usando el script PHP y enviar WhatsApp
          try {
            const idUsuario = user?.id_usuario || 0;
            const generatorUrl = window.location.origin + `/php/guiaPdfImpresion.php?id_guia=${idGuia}&id_usuario_global=${idUsuario}`;

            // Llamar al PHP para generar el PDF
            await axios.get(generatorUrl);

            // Usar la ruta del archivo físico
            const fullPdfUrl = window.location.origin + `/php/tmp/guiaImpresion_${idGuia}.pdf`;

            if (metodoImpresion === 'directa') {
              try {
                if (!printerGuias) {
                  toast.error('No hay impresora de guías configurada');
                  setPdfTitle(`Guía N° ${idGuia}`);
                  setPdfUrl(fullPdfUrl);
                  setPdfModalOpen(true);
                } else {
                  const loadQZ = () => new Promise((resolve, reject) => {
                    if (window.qz) return resolve();
                    const s = document.createElement('script');
                    s.src = '/qz.js';
                    s.onload = () => resolve();
                    s.onerror = () => reject(new Error('No se pudo cargar qz.js'));
                    document.head.appendChild(s);
                  });

                  const configurarQZ = () => {
                    if (!window.qz) return;
                    qz.security.setSignatureAlgorithm('SHA256');
                    qz.security.setCertificatePromise((resolve) => {
                      fetch('/digital-certificate.crt', { cache: 'no-store', headers: { 'Cache-Control': 'no-cache' } })
                        .then(r => r.ok ? r.text() : null).then(resolve).catch(() => resolve(null));
                    });
                    qz.security.setSignaturePromise((toSign) => (resolve) => {
                      api.get('/configuracion/sign-message', { params: { request: toSign } })
                        .then(res => resolve(res.data))
                        .catch(err => {
                          console.error('Error signing message', err);
                          resolve(null);
                        });
                    });
                  };

                  const conectarQZ = () => {
                    if (!window.qz) return Promise.reject('Librería no cargada');
                    if (qz.websocket.isActive()) return Promise.resolve();
                    const TIMEOUT_MS = 3000;
                    let timeoutId;
                    const timeoutPromise = new Promise((_, reject) => {
                      timeoutId = setTimeout(() => reject(new Error('Timeout')), TIMEOUT_MS);
                    });
                    return Promise.race([
                      qz.websocket.connect({ retries: 0, delay: 0, usingSecure: false }),
                      timeoutPromise
                    ]).finally(() => clearTimeout(timeoutId));
                  };

                  await loadQZ();
                  configurarQZ();
                  await conectarQZ();

                  const config = window.qz.configs.create(printerGuias, {
                    scaleContent: true,
                    units: 'mm',
                    margins: { top: 0, bottom: 0, left: 8, right: 2 }
                  });
                  const data = [{
                    type: 'pixel',
                    format: 'pdf',
                    flavor: 'file',
                    data: fullPdfUrl
                  }];
                  await window.qz.print(config, data);
                  toast.success('Guía impresa en ' + printerGuias);
                }
              } catch (e) {
                console.error('[QZ] Error al imprimir:', e);
                toast.error('Error al imprimir vía QZ Tray. Abriendo PDF manual...');
                setPdfTitle(`Guía N° ${idGuia}`);
                setPdfUrl(fullPdfUrl);
                setPdfModalOpen(true);
              }
            } else {
              setPdfTitle(`Guía N° ${idGuia}`);
              setPdfUrl(fullPdfUrl);
              setPdfModalOpen(true);
            }

            // Enviar WhatsApp al destinatario y remitente
            const telefonosAEnviar = [];

            const celDest = (destinatario?.telefono || destinatario?.telefono2 || '').replace(/\D/g, '');
            if (celDest.length >= 9) {
              telefonosAEnviar.push({ numero: celDest, nombre: destinatario?.nombres || 'cliente' });
            }

            const celRem = (remitente?.telefono || '').replace(/\D/g, '');
            if (celRem.length >= 9 && celRem !== celDest) {
              telefonosAEnviar.push({ numero: celRem, nombre: remitente?.nombres || 'cliente' });
            }

            const empDataStr = sessionStorage.getItem('empresa_data');
            const empData = empDataStr ? JSON.parse(empDataStr) : null;
            const enviarWhatsapp = empData ? empData.enviar_whatsapp === 1 : false;

            if (enviarWhatsapp) {
              for (const t of telefonosAEnviar) {
                try {
                  const mensajeGuia = `Estimado(a) ${t.nombre},\n\nAdjuntamos la guía N° ${idGuia} de su encomienda. ¡Gracias por preferirnos!`;
                  await api.post('/whatsapp/enviar', {
                    number: t.numero,
                    message: mensajeGuia,
                    fileUrl: fullPdfUrl
                  });
                } catch (e) {
                  console.error('Error enviando WhatsApp guia a ' + t.numero, e);
                }
              }
              if (telefonosAEnviar.length > 0) {
                toast.success('Guía enviada por WhatsApp');
              }
            }
          } catch (err) {
            console.error('Error abriendo PDF de guía:', err);
            toast.error('No se pudo abrir el PDF');
          }
        }
        setTimeout(() => handleResetForm(), 500);
      } else {
        toast.error(result?.data || 'Error al guardar la guía');
      }
    } catch (error) {
      console.error('Error guardando guía:', error);
      toast.error(error?.response?.data?.message || 'Error al guardar la guía');
    } finally {
      setSaving(false);
    }
  };

  // ── Reset form for next guía ─────────────────────────
  const handleResetForm = () => {
    setFieldErrors({});
    setOrigen(origenOriginalRef.current);
    setDestino('');
    setDestinoTexto('');
    setTipoEnvio('');
    setRemitente(null);
    setDestinatario(null);
    setFacturarA('1');
    setConvenio(null);
    setCompania(null);
    setDetalles([]);
    setDescuentoTipo('0');
    setValorDeclaradoActivo(false);
    setValorDeclaradoPorcentaje('');
    setValorDeclaradoValor('');
    setNumeroManual(false);
    setNumeroManualGuia('');
    setPagos([]);
    setPagadoPor('1');
    setObservacion('');
    setOtrosIdentidad('');
    setOtrosNombre('');
    setOtrosTelefono('');
    setOtrosCorreo('');
    setOtrosDireccion('');
    setSelectedTipoEnvioObj(null);
    toast.success('Formulario listo para nueva guía');
  };

  // ── Handler Cancelar (confirmación como ExtJS) ────────
  const handleCancelar = async () => {
    const hasChanges = remitente || destinatario || detalles.length > 0 || observacion;
    if (hasChanges) {
      const confirmCancel = await Swal.fire({ title: '¿Cancelar?', text: '¿Desea cancelar la guía? Se perderán los cambios.', icon: 'warning', showCancelButton: true, confirmButtonText: 'Sí, cancelar', cancelButtonText: 'No' });
      if (!confirmCancel.isConfirmed) return;
    }
    navigate('/guias');
  };

  if (cajaChecking || loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Cargando formulario...</p>
        </div>
      </div>
    );
  }

  const cardClass = "bg-white rounded-xl shadow-sm border border-slate-200/80";
  const inputClass = "w-full h-8 px-2.5 text-xs border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-400 bg-white text-slate-700 transition-all duration-150";
  const inputRO = `${inputClass} bg-slate-50 cursor-not-allowed text-slate-400 border-dashed`;
  const labelClass = "block text-[10px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5";
  const sectionTitle = { fontSize: '13px', fontWeight: 700, color: '#0f172a', marginBottom: '12px', display: 'flex', alignItems: 'center', gap: '10px', letterSpacing: '-0.01em' };
  const sectionIcon = { width: '26px', height: '26px', borderRadius: '7px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '11px' };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-slate-50 to-slate-100/60">
      {/* ── CABECERA ─────────────────────────────────────── */}
      <div className="bg-white border-b border-slate-200/80 shadow-sm shrink-0">
        <div className="flex items-center justify-between px-5 py-3">
          <div className="flex items-center gap-3.5">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-emerald-500 to-emerald-600 text-white flex items-center justify-center shadow-md shadow-emerald-200">
              <i className="fas fa-plus-circle text-sm"></i>
            </div>
            <div>
              <h1 className="text-sm font-extrabold text-slate-800 uppercase tracking-tight leading-none">{isEditing ? `Editar Guía N° ${idGuiaEdit}` : 'Nueva Guía'}</h1>
              <p className="text-[10px] font-semibold text-slate-400 uppercase tracking-widest mt-0.5">{isEditing ? 'Modificación de Encomienda' : 'Registro de Encomienda'}</p>
            </div>
          </div>
        </div>
      </div>

      {/* ── CONTENIDO SCROLLABLE ──────────────────────────── */}
      <div className="flex-1 overflow-y-auto p-5 space-y-5">

        {/* ═══════════════════════════════════════════════════
            FILA 1: Info Básica (50%) + Datos Compañía (50%)
            ExtJS: layout column 50/50
        ═══════════════════════════════════════════════════ */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          {/* Info Básica */}
          <div className={cardClass} style={{ padding: '16px' }}>
            <h3 style={sectionTitle}>
              <div style={{ ...sectionIcon, background: 'linear-gradient(135deg, #eef2ff, #e0e7ff)' }}>
                <i className="fas fa-map-marker-alt" style={{ color: '#4f46e5', fontSize: '11px' }}></i>
              </div>
              Datos de la Guía
            </h3>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '10px' }}>
              {/* Origen = nombre_canton del usuario (read-only, NO sucursal) */}
              <div>
                <label className={labelClass}>Origen *</label>
                <input type="text" className={fieldErrors.origen ? `${inputRO} border-2 border-red-400 ring-2 ring-red-200` : inputRO} readOnly value={origen} placeholder="Cargando..." />
              </div>
              {/* Destino (autocomplete escribible) */}
              <div style={{ position: 'relative' }}>
                <label className={labelClass}>Destino *</label>
                <div style={{ display: 'flex', gap: '4px', alignItems: 'center' }}>
                  <input type="text" className={fieldErrors.destino ? `${inputClass} border-2 border-red-400` : inputClass} style={{ flex: 1 }}
                    value={destinoTexto}
                    onChange={(e) => {
                      const val = e.target.value;
                      setDestinoTexto(val);
                      setDestino(''); // Limpiar selección mientras escribe
                      setFieldErrors(prev => ({ ...prev, destino: undefined }));
                      setDestinoAbierto(true);
                    }}
                    onFocus={() => {
                      setDestinoAbierto(true);
                    }}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') {
                        e.preventDefault();
                        const filtrados = destinos.filter(d => (d.nombre || d.nombre_destino || '').toLowerCase().includes(destinoTexto.toLowerCase()));
                        if (filtrados.length > 0) {
                          const primero = filtrados[0];
                          handleSetDestino(String(primero.id || primero.id_destino), primero.nombre || primero.nombre_destino || '');
                        }
                        setDestinoAbierto(false);
                      }
                    }}
                    onBlur={() => setTimeout(() => setDestinoAbierto(false), 200)}
                    placeholder="Escriba para buscar destino..." />
                  <button onClick={async () => {
                    try {
                      const res = await GuiaService.getDestinosCombo();
                      setDestinos(res?.data || []);
                      toast.success('Destinos actualizados');
                    } catch (e) {
                      toast.error('Error al actualizar destinos');
                    }
                  }} className="h-8 w-8 flex items-center justify-center bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-md text-xs" title="Refrescar destinos">
                    <i className="fas fa-sync-alt"></i>
                  </button>
                </div>
                {destinoAbierto && (
                  <div style={{ position: 'absolute', top: '100%', left: 0, right: '42px', zIndex: 50, background: 'white', border: '1px solid #e2e8f0', borderRadius: '8px', maxHeight: '200px', overflowY: 'auto', boxShadow: '0 4px 16px rgba(0,0,0,0.1)' }}>
                    {destinos.filter(d => {
                      const txt = (d.nombre || d.nombre_destino || '').toLowerCase();
                      return txt.includes(destinoTexto.toLowerCase());
                    }).map(d => (
                      <div key={d.id || d.id_destino}
                        onMouseDown={() => {
                          const nombre = d.nombre || d.nombre_destino || '';
                          handleSetDestino(String(d.id || d.id_destino), nombre);
                          setDestinoAbierto(false);
                        }}
                        style={{ padding: '8px 12px', cursor: 'pointer', fontSize: '12px', borderBottom: '1px solid #f1f5f9', transition: 'background 0.1s' }}
                        onMouseEnter={(e) => e.currentTarget.style.background = '#f1f5f9'}
                        onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}>
                        {d.nombre || d.nombre_destino}
                      </div>
                    ))}
                    {destinos.filter(d => (d.nombre || d.nombre_destino || '').toLowerCase().includes(destinoTexto.toLowerCase())).length === 0 && (
                      <div style={{ padding: '10px 12px', fontSize: '11px', color: '#94a3b8', fontStyle: 'italic' }}>Sin resultados</div>
                    )}
                  </div>
                )}
              </div>
              {/* A quién se factura */}
              <div>
                <label className={labelClass}>A quién se factura</label>
                <select className={inputClass} value={facturarA} onChange={(e) => setFacturarA(e.target.value)}>
                  <option value="1">Remitente</option>
                  <option value="2">Destinatario</option>
                  <option value="3">Otros</option>
                </select>
              </div>
            </div>
            {/* Observación - dentro de Info Básica como en ExtJS */}
            <div style={{ marginTop: '10px' }}>
              <label className={labelClass}>Observación</label>
              <textarea
                className={inputClass} rows="2"
                placeholder="Observaciones de la guía (opcional)..."
                value={observacion}
                onChange={(e) => setObservacion(e.target.value)}
                style={{ resize: 'vertical', minHeight: '36px', paddingTop: '6px' }}
              ></textarea>
            </div>
          </div>

          {/* Compañía */}
          <CompaniaPanel
            cliente={remitente}
            compania={compania}
            onSeleccionarCompania={handleSetCompania}
            error={fieldErrors.compania}
            destinos={destinos}
            onSeleccionarDestino={(id, txt) => handleSetDestino(id, txt)}
          />
        </div>

        {/* ═══════════════════════════════════════════════════
            FILA 2: Remitente (33%) + Destinatario (33%) + Otros (33%)
            ExtJS: layout column 0.33/0.33/0.33
        ═══════════════════════════════════════════════════ */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '12px' }}>
          <RemitenteDestinatarioForm
            tipo="Remitente"
            cliente={remitente}
            onChange={handleSetRemitente}
            onConvenioFound={handleConvenioFound}
            onDestinatarioAutoFill={handleDestinatarioAutoFill}
            error={fieldErrors.remitente}
          />
          <RemitenteDestinatarioForm
            tipo="Destinatario"
            cliente={destinatario}
            onChange={handleSetDestinatario}
            remitenteId={remitente?.id_cliente}
            error={fieldErrors.destinatario}
          />

          {/* ── OTROS (tercera persona) ──────────────────── */}
          <div className={cardClass} style={{ padding: '16px', opacity: facturarA !== '3' ? 0.5 : 1 }}>
            <h3 style={sectionTitle}>
              <div style={{ ...sectionIcon, background: 'linear-gradient(135deg, #fef3c7, #fde68a)' }}>
                <i className="fas fa-user-friends" style={{ color: '#d97706', fontSize: '11px' }}></i>
              </div>
              Otros
            </h3>

            {/* Identidad + Botones */}
            <div style={{ display: 'flex', gap: '4px', marginBottom: '10px' }}>
              <input type="text" className={inputClass} placeholder="Identidad..."
                value={otrosIdentidad} onChange={(e) => setOtrosIdentidad(e.target.value.replace(/\D/g, ''))}
                disabled={facturarA !== '3'}
                style={{ flex: 1 }} />
              <button onClick={handleBuscarOtros} disabled={otrosLoading || facturarA !== '3'}
                className="h-8 px-2 bg-indigo-500 hover:bg-indigo-600 text-white rounded-md text-xs font-bold shadow-sm disabled:opacity-50"
                title="Buscar cliente">
                <i className={`fas ${otrosLoading ? 'fa-spinner fa-spin' : 'fa-search'}`}></i>
              </button>
              <button onClick={() => setOtrosShowCreate(true)}
                disabled={facturarA !== '3'}
                className="h-8 px-2 bg-amber-500 hover:bg-amber-600 text-white rounded-md text-xs font-bold shadow-sm disabled:opacity-50"
                title="Nuevo cliente">
                <i className="fas fa-user-plus"></i>
              </button>
            </div>

            {otrosShowCreate ? (
              <div style={{ padding: '10px', background: '#f8fafc', borderRadius: '8px', marginBottom: '10px' }}>
                <h4 style={{ fontSize: '12px', fontWeight: 700, marginBottom: '8px', color: '#334155' }}>
                  <i className="fas fa-user-plus"></i> Crear Otros
                </h4>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px' }}>
                  <div>
                    <label className={labelClass}>Identificación *</label>
                    <input className={inputClass} value={otrosNewCliente.identificacion_cliente}
                      onChange={(e) => setOtrosNewCliente({ ...otrosNewCliente, identificacion_cliente: e.target.value.replace(/\D/g, '') })}
                      maxLength={13} />
                  </div>
                  <div>
                    <label className={labelClass}>Tipo ID</label>
                    <select className={inputClass} value={otrosNewCliente.tipo_identificacion_cliente}
                      onChange={(e) => setOtrosNewCliente({ ...otrosNewCliente, tipo_identificacion_cliente: e.target.value })}>
                      <option value="C">Cédula</option>
                      <option value="R">RUC</option>
                      <option value="P">Pasaporte</option>
                    </select>
                  </div>
                  <div style={{ gridColumn: 'span 2' }}>
                    <label className={labelClass}>Nombre / Razón Social *</label>
                    <input className={inputClass} value={otrosNewCliente.nombre_cliente}
                      onChange={(e) => setOtrosNewCliente({ ...otrosNewCliente, nombre_cliente: e.target.value.toUpperCase() })} />
                  </div>
                  <div>
                    <label className={labelClass}>Dirección</label>
                    <input className={inputClass} value={otrosNewCliente.direccion_cliente}
                      onChange={(e) => setOtrosNewCliente({ ...otrosNewCliente, direccion_cliente: e.target.value.toUpperCase() })} />
                  </div>
                  <div>
                    <label className={labelClass}>Teléfono</label>
                    <input className={inputClass} value={otrosNewCliente.telefono_cliente}
                      onChange={(e) => setOtrosNewCliente({ ...otrosNewCliente, telefono_cliente: e.target.value.replace(/\D/g, '') })} />
                  </div>
                  <div style={{ gridColumn: 'span 2' }}>
                    <label className={labelClass}>Email</label>
                    <input className={inputClass} type="email" value={otrosNewCliente.email_cliente}
                      onChange={(e) => setOtrosNewCliente({ ...otrosNewCliente, email_cliente: e.target.value })} />
                  </div>
                </div>
                <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end', marginTop: '10px' }}>
                  <button onClick={() => setOtrosShowCreate(false)}
                    className="px-3 py-1.5 border border-slate-200 text-slate-600 rounded-md hover:bg-slate-50 text-xs font-bold">
                    Cancelar
                  </button>
                  <button onClick={handleNuevoClienteOtros} disabled={otrosLoading}
                    className="px-3 py-1.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-md text-xs font-bold shadow-sm disabled:opacity-70">
                    {otrosLoading ? <><i className="fas fa-spinner fa-spin"></i> Guardando...</> : <><i className="fas fa-save"></i> Guardar</>}
                  </button>
                </div>
              </div>
            ) : (
              <>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '8px' }}>
                  <div style={{ gridColumn: 'span 2' }}>
                    <label className={labelClass}>Razón Social</label>
                    <input type="text" className={inputRO} readOnly value={otrosNombre} />
                  </div>
                  <div>
                    <label className={labelClass}>Teléfono</label>
                    <input type="text" className={inputRO} readOnly value={otrosTelefono} />
                  </div>
                  <div>
                    <label className={labelClass}>Correo</label>
                    <input type="text" className={inputRO} readOnly value={otrosCorreo} />
                  </div>
                  <div style={{ gridColumn: 'span 2' }}>
                    <label className={labelClass}>Dirección</label>
                    <input type="text" className={inputRO} readOnly value={otrosDireccion} />
                  </div>
                </div>

                <button onClick={handleLimpiarOtros}
                  className="w-full h-7 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-md text-[10px] font-bold">
                  <i className="fas fa-eraser mr-1"></i> Limpiar
                </button>
              </>
            )}
          </div>
        </div>

        {/* ═══════════════════════════════════════════════════
            FILA 3: Encomienda (50%) + Forma de Pago (50%)
            ExtJS: layout column 50/50
        ═══════════════════════════════════════════════════ */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', alignItems: 'start' }}>

          {/* ── Encomienda: Detalle + Valor Declarado + Número Manual ── */}
          <div className={cardClass} style={{ padding: '16px' }}>
            <h3 style={sectionTitle}>
              <div style={{ ...sectionIcon, background: 'linear-gradient(135deg, #fef3c7, #fde68a)' }}>
                <i className="fas fa-box-open" style={{ color: '#d97706', fontSize: '11px' }}></i>
              </div>
              ENCOMIENDA
              {detalles.length > 0 && <span style={{ fontSize: '10px', fontWeight: 600, color: '#94a3b8', background: '#f1f5f9', padding: '2px 8px', borderRadius: '10px' }}>{detalles.length} bulto{detalles.length !== 1 ? 's' : ''}</span>}
            </h3>

            {/* DETALLES + TOTAL header (como ExtJS) */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px', padding: '6px 10px', background: '#f8fafc', borderRadius: '6px', border: '1px solid #e2e8f0' }}>
              <span style={{ fontWeight: 700, fontSize: '16px', color: '#1e293b', letterSpacing: '0.05em' }}>DETALLES</span>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <span style={{ fontWeight: 600, fontSize: '11px', color: '#6366f1' }}>TOTAL:</span>
                <span style={{ fontWeight: 800, fontSize: '18px', color: '#6366f1' }}>
                  ${detalles.reduce((s, d) => s + (d.total || 0), 0).toFixed(2)}
                </span>
              </div>
            </div>
            {/* Tipo de Envío - dentro de ENCOMIENDA como en ExtJS */}
            <div style={{ marginBottom: '10px' }}>
              <label className={labelClass}>Tipo de Envío *</label>
              <select className={fieldErrors.tipoEnvio ? `${inputClass} border-2 border-red-400` : inputClass} value={tipoEnvio} onChange={(e) => {
                const val = e.target.value;
                handleSetTipoEnvio(val);
                const obj = tiposEnvio.find(t => String(t.id || t.value) === val);
                setSelectedTipoEnvioObj(obj || null);
              }}>
                <option value="">Seleccione tipo...</option>
                {tiposEnvio.map(t => (
                  <option key={t.id || t.value || t.id_tipo_envio} value={t.id || t.value || t.id_tipo_envio}>
                    {t.nombre || t.label || t.text}
                  </option>
                ))}
              </select>
            </div>
            <DetalleCargaGrid
              detalles={detalles}
              onChange={handleSetDetalles}
              convenio={convenio}
              costoEnvioPorDefecto={selectedTipoEnvioObj?.costo_envio}
              tiposEnvio={tiposEnvio}
              tipoEnvioId={tipoEnvio}
              error={fieldErrors.detalles}
              cobrarIvaGuia={cobrarIvaGuia}
            />

            {/* ── Número Manual ──────────────────────────── */}
            <div style={{ marginTop: '12px', display: 'flex', alignItems: 'center', gap: '8px', padding: '8px', background: '#f8fafc', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
              <label style={{ display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer', fontSize: '11px', color: '#475569', fontWeight: 600 }}>
                <input type="checkbox" checked={numeroManual} onChange={(e) => setNumeroManual(e.target.checked)}
                  className="w-4 h-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500" />
                Número Manual
              </label>
              {numeroManual && (
                <input type="text" className={inputClass} style={{ width: '120px' }}
                  value={numeroManualGuia} onChange={(e) => setNumeroManualGuia(e.target.value)}
                  placeholder="# Guía" />
              )}
            </div>

            {/* ── Valor Declarado ────────────────────────── */}
            <div style={{ marginTop: '10px', padding: '10px 12px', background: '#f8fafc', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
              <label style={{ fontSize: '10px', fontWeight: 700, color: '#475569', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '8px', display: 'block' }}>
                Valor Declarado
              </label>
              <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', padding: '4px 10px', borderRadius: '6px', border: `1.5px solid ${!valorDeclaradoActivo ? '#6366f1' : '#e2e8f0'}`, background: !valorDeclaradoActivo ? '#eef2ff' : 'transparent', fontSize: '11px', fontWeight: 600, color: !valorDeclaradoActivo ? '#4f46e5' : '#64748b' }}>
                  <input type="radio" name="valorDeclarado" checked={!valorDeclaradoActivo}
                    onChange={() => setValorDeclaradoActivo(false)} />
                  Sin valor
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', padding: '4px 10px', borderRadius: '6px', border: `1.5px solid ${valorDeclaradoActivo ? '#f59e0b' : '#e2e8f0'}`, background: valorDeclaradoActivo ? '#fef3c7' : 'transparent', fontSize: '11px', fontWeight: 600, color: valorDeclaradoActivo ? '#d97706' : '#64748b' }}>
                  <input type="radio" name="valorDeclarado" checked={valorDeclaradoActivo}
                    onChange={() => setValorDeclaradoActivo(true)} />
                  Con valor
                </label>
                {valorDeclaradoActivo && (
                  <>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                      <input type="text" inputMode="decimal" className={inputClass} style={{ width: '70px' }}
                        value={valorDeclaradoPorcentaje}
                        onChange={(e) => setValorDeclaradoPorcentaje(sanitizeNum(e.target.value))}
                        placeholder="%" />
                      <span style={{ fontSize: '10px', fontWeight: 600, color: '#64748b' }}>%</span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                      <input type="text" inputMode="decimal" className={inputClass} style={{ width: '100px' }}
                        value={valorDeclaradoValor}
                        onChange={(e) => setValorDeclaradoValor(sanitizeNum(e.target.value))}
                        placeholder="$ 0.00" />
                      <span style={{ fontSize: '10px', fontWeight: 600, color: '#64748b' }}>$</span>
                    </div>
                  </>
                )}
              </div>
            </div>
          </div>

          {/* ── Columna Derecha: Descuento + Forma de Pago ── */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {/* Descuento */}
            <div className={cardClass} style={{ padding: '16px' }}>
              <h3 style={sectionTitle}>
                <div style={{ ...sectionIcon, background: 'linear-gradient(135deg, #fce7f3, #fbcfe8)' }}>
                  <i className="fas fa-percentage" style={{ color: '#db2777', fontSize: '11px' }}></i>
                </div>
                Descuento
              </h3>
              <div style={{ display: 'flex', gap: '16px', fontSize: '11px', color: '#475569' }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', padding: '8px 12px', borderRadius: '8px', border: `2px solid ${descuentoTipo === '0' ? '#6366f1' : '#e2e8f0'}`, background: descuentoTipo === '0' ? '#eef2ff' : 'white' }}>
                  <input type="radio" name="descuento" value="0" checked={descuentoTipo === '0'}
                    onChange={(e) => setDescuentoTipo(e.target.value)} />
                  Tarifa Normal
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', padding: '8px 12px', borderRadius: '8px', border: `2px solid ${descuentoTipo === '1' ? '#f59e0b' : '#e2e8f0'}`, background: descuentoTipo === '1' ? '#fef3c7' : 'white', opacity: convenio || parseInt(configTipoTarifa) !== 0 ? 1 : 0.6 }}>
                  <input type="radio" name="descuento" value="1" checked={descuentoTipo === '1'}
                    onChange={(e) => setDescuentoTipo(e.target.value)} disabled={!convenio && parseInt(configTipoTarifa) === 0} />
                  Tarifa 50%
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: '4px', cursor: 'pointer', padding: '8px 12px', borderRadius: '8px', border: `2px solid ${descuentoTipo === '2' ? '#10b981' : '#e2e8f0'}`, background: descuentoTipo === '2' ? '#d1fae5' : 'white', opacity: convenio || parseInt(configTipoTarifa) !== 0 ? 1 : 0.6 }}>
                  <input type="radio" name="descuento" value="2" checked={descuentoTipo === '2'}
                    onChange={(e) => setDescuentoTipo(e.target.value)} disabled={!convenio && parseInt(configTipoTarifa) === 0} />
                  Cortesía 100%
                </label>
              </div>
            </div>

            {/* ── Forma de Pago ───────────────────────────── */}
            {!isEditing ? (
              <FormaPagoPanel
                detalles={detalles}
                convenio={convenio}
                onPagosChange={setPagos}
                pagadoPor={pagadoPor}
                onPagadoPorChange={setPagadoPor}
                defaultFormaPagoId={defaultFormaPagoId}
                configTipoTarifa={configTipoTarifa}
              />
            ) : (
              <div className={cardClass} style={{ padding: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#f8fafc' }}>
                <div className="text-center text-slate-400">
                  <i className="fas fa-lock text-2xl mb-2"></i>
                  <p className="text-xs font-semibold uppercase tracking-wider mt-2">Pagos deshabilitados en edición</p>
                  <p className="text-[10px] opacity-75">Para modificar los pagos, anule y genere una nueva guía.</p>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* ═══════════════════════════════════════════════════
            FILA 4: Totales
        ═══════════════════════════════════════════════════ */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', alignItems: 'start' }}>

          <div></div>

          {/* Totales */}
          <TotalesPanel
            detalles={detalles}
            descuentoTipo={descuentoTipo}
            tiposEnvio={tiposEnvio}
            cobrarIvaGuia={cobrarIvaGuia}
          />
        </div>

        {/* Hidden fields para compatibilidad con ExtJS */}
        <input type="hidden" name="total" value={detalles.reduce((s, d) => s + (d.total || 0), 0)} />
        <input type="hidden" name="tipodescuento" value={descuentoTipo} />

      </div>

      {/* ═══════════════════════════════════════════════════
          FILA 5: Totales + Botones Guardar / Cancelar (sticky)
      ═══════════════════════════════════════════════════ */}
      <div style={{ position: 'sticky', bottom: 0, background: 'white', borderTop: '2px solid #e2e8f0', boxShadow: '0 -6px 20px rgba(0,0,0,0.08)', zIndex: 40, flexShrink: 0 }}>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'stretch', padding: '10px 28px' }}>

          {/* ── Contenedor Izquierdo: Totales ──────────────── */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>

            {/* Cantidad de items */}
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '4px 12px', background: '#f1f5f9', borderRadius: '8px', minWidth: '60px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Cantidad</span>
              <span style={{ fontSize: '16px', fontWeight: 800, color: '#334155' }}>{detalles.length}</span>
            </div>

            <div style={{ width: '1px', height: '32px', background: '#cbd5e1' }}></div>

            {/* Precio Unitario (promedio) */}
            <div style={{ display: 'flex', flexDirection: 'column', padding: '4px 8px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.08em' }}>P. Unit.</span>
              <span style={{ fontFamily: 'monospace', fontSize: '14px', fontWeight: 700, color: '#475569' }}>
                ${(() => {
                  const totalC = detalles.reduce((s, d) => s + (d.cantidad || 1), 0);
                  const totalP = detalles.reduce((s, d) => s + ((d.precioUnitario || 0) * (d.cantidad || 1)), 0);
                  return totalC > 0 ? (totalP / totalC).toFixed(2) : '0.00';
                })()}
              </span>
            </div>

            <div style={{ width: '1px', height: '32px', background: '#cbd5e1' }}></div>

            {/* Subtotal */}
            <div style={{ display: 'flex', flexDirection: 'column', padding: '4px 8px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Subtotal</span>
              <span style={{ fontFamily: 'monospace', fontSize: '14px', fontWeight: 700, color: '#475569' }}>
                ${(() => {
                  const st12 = detalles.reduce((s, d) => s + ((d.precioUnitario || 0) * (d.cantidad || 1)), 0);
                  return st12.toFixed(2);
                })()}
              </span>
            </div>

            {/* Descuento */}
            <div style={{ display: 'flex', flexDirection: 'column', padding: '4px 8px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Desc.</span>
              <span style={{ fontFamily: 'monospace', fontSize: '14px', fontWeight: 700, color: '#16a34a' }}>
                ${(() => {
                  const st12 = detalles.reduce((s, d) => s + ((d.precioUnitario || 0) * (d.cantidad || 1)), 0);
                  if (descuentoTipo === '2') return st12.toFixed(2);
                  if (descuentoTipo === '1') return (st12 * 0.50).toFixed(2);
                  return detalles.reduce((s, d) => s + (d.descuento || 0), 0).toFixed(2);
                })()}
              </span>
            </div>

            {/* IVA */}
            <div style={{ display: 'flex', flexDirection: 'column', padding: '4px 8px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.08em' }}>IVA</span>
              <span style={{ fontFamily: 'monospace', fontSize: '14px', fontWeight: 700, color: '#475569' }}>
                ${(() => {
                  if (!cobrarIvaGuia) return '0.00';
                  return detalles.reduce((s, d) => s + (d.iva || 0), 0).toFixed(2);
                })()}
              </span>
            </div>

            {/* Tarifa */}
            <div style={{ display: 'flex', flexDirection: 'column', padding: '4px 8px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Tarifa</span>
              <span style={{ fontFamily: 'monospace', fontSize: '14px', fontWeight: 700, color: '#475569' }}>
                ${detalles.reduce((s, d) => s + (d.tarifa || 0), 0).toFixed(2)}
              </span>
            </div>

            <div style={{ width: '1px', height: '32px', background: '#cbd5e1' }}></div>

            {/* Total a Pagar */}
            <div style={{ display: 'flex', flexDirection: 'column', padding: '4px 12px', background: '#f0fdf4', borderRadius: '8px', minWidth: '100px' }}>
              <span style={{ fontSize: '9px', fontWeight: 700, color: '#059669', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Total a Pagar</span>
              <span style={{ fontFamily: 'monospace', fontSize: '20px', fontWeight: 900, color: '#059669' }}>
                ${(() => {
                  const st12 = detalles.reduce((s, d) => s + ((d.precioUnitario || 0) * (d.cantidad || 1)), 0);
                  let desc = 0;
                  if (descuentoTipo === '2') desc = st12;
                  else if (descuentoTipo === '1') desc = st12 * 0.50;
                  else desc = detalles.reduce((s, d) => s + (d.descuento || 0), 0);
                  const stDesc = st12 - desc;
                  const tarifa = detalles.reduce((s, d) => s + (d.tarifa || 0), 0);
                  const ivaTotal = calcGuardarIva(detalles, descuentoTipo, tiposEnvio, cobrarIvaGuia);
                  return (stDesc + ivaTotal + tarifa).toFixed(2);
                })()}
              </span>
            </div>

          </div>

          {/* ── Contenedor Derecho: Estado cobro + Botones ── */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>

            {/* Estado de cobro */}
            {(() => {
              const st12 = detalles.reduce((s, d) => s + ((d.precioUnitario || 0) * (d.cantidad || 1)), 0);
              let desc = 0;
              if (descuentoTipo === '2') desc = st12;
              else if (descuentoTipo === '1') desc = st12 * 0.50;
              else desc = detalles.reduce((s, d) => s + (d.descuento || 0), 0);
              const ivaTotal = calcGuardarIva(detalles, descuentoTipo, tiposEnvio, cobrarIvaGuia);
              const totalG = st12 - desc + ivaTotal + detalles.reduce((s, d) => s + (d.tarifa || 0), 0);
              const totalPagado = pagos.reduce((s, p) => s + (parseFloat(p.monto) || 0), 0);
              const cobrado = totalPagado >= totalG && totalG > 0;
              return (
                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', background: cobrado ? '#f0fdf4' : '#fffbeb', padding: '6px 12px', borderRadius: '8px' }}>
                  <i className={`fas ${cobrado ? 'fa-check-circle' : 'fa-hourglass-half'}`}
                    style={{ color: cobrado ? '#059669' : '#f59e0b', fontSize: '14px' }}></i>
                  <span style={{ fontSize: '13px', fontWeight: 800, color: cobrado ? '#059669' : '#d97706' }}>
                    {cobrado ? 'Cobrado' : 'No cobrado'}
                  </span>
                </div>
              );
            })()}

            {/* Botones */}
            <button onClick={handleCancelar}
              style={{ background: 'linear-gradient(135deg, #ef4444, #dc2626)', borderRadius: '10px', width: '140px', height: '40px', fontSize: '13px', fontWeight: 700, color: 'white', border: 'none', cursor: 'pointer', boxShadow: '0 4px 14px rgba(239,68,68,0.3)', letterSpacing: '0.02em', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', transition: 'all 0.15s' }}>
              <i className="fas fa-window-close"></i>Cancelar
            </button>
            <button onClick={handleGuardar} disabled={saving}
              style={{ background: 'linear-gradient(135deg, #059669, #047857)', borderRadius: '10px', width: '140px', height: '40px', fontSize: '13px', fontWeight: 700, color: 'white', border: 'none', cursor: saving ? 'wait' : 'pointer', boxShadow: '0 4px 14px rgba(5,150,105,0.35)', letterSpacing: '0.02em', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', transition: 'all 0.15s' }}>
              {saving ? <><i className="fas fa-spinner fa-spin"></i>Procesando...</> : <><i className="fas fa-save"></i>Guardar</>}
            </button>
          </div>

        </div>

      </div>

      {/* ── Modal PDF de impresión ──────────────────────── */}
      <PdfViewerModal
        open={pdfModalOpen}
        onClose={() => { setPdfModalOpen(false); setPdfUrl(null); }}
        url={pdfUrl}
        title={pdfTitle}
        showPrintButton={true}
      />

      {/* ── Modal Apertura de Caja ────────────────────────── */}
      <Modal isOpen={showCajaModal} onClose={handleCerrarModalCaja} title="Apertura de Caja" width="max-w-2xl">
        <AperturaCajaForm
          onSubmit={handleCrearCaja}
          onCancel={handleCerrarModalCaja}
        />
      </Modal>
      {/* Modal Selección Múltiple Compañías */}
      <Modal isOpen={showMultiCompaniaModal} onClose={() => setShowMultiCompaniaModal(false)} title="Seleccionar Compañía" width="max-w-md">
        <div className="p-4">
          <p className="text-sm text-slate-600 mb-4">El destino seleccionado tiene múltiples compañías asociadas. Por favor seleccione una:</p>
          <div className="flex flex-col gap-2 max-h-[50vh] overflow-y-auto">
            {multiCompaniaOptions.map((opt, idx) => (
              <div key={idx}
                onClick={() => {
                  if (opt.idfk_compania_asociada_destino) {
                    setCompania({
                      id: opt.idfk_compania_asociada_destino,
                      id_compania_asociada: opt.idfk_compania_asociada_destino,
                      nombre: opt.nombre_compania_asociada || '',
                      ruc: opt.ruc_compania_asociada || opt.ruc_compania || opt.ruc || '',
                      telefono: opt.numero_contacto || '',
                      correo: ''
                    });
                  } else {
                    setCompania(null);
                  }
                  setShowMultiCompaniaModal(false);
                }}
                className="p-3 border border-slate-200 rounded-lg hover:bg-indigo-50 hover:border-indigo-200 cursor-pointer transition-colors flex justify-between items-center group"
              >
                <div>
                  <div className="text-sm font-bold text-slate-800 group-hover:text-indigo-700">
                    <i className="fas fa-building text-slate-400 mr-2 group-hover:text-indigo-500"></i>
                    {opt.nombre_compania_asociada || 'Sin compañía'}
                  </div>
                  {opt.ruc_compania_asociada && (
                    <div className="text-[10px] text-slate-500 mt-1">RUC: {opt.ruc_compania_asociada}</div>
                  )}
                </div>
                <i className="fas fa-chevron-right text-slate-300 group-hover:text-indigo-400"></i>
              </div>
            ))}
          </div>
        </div>
      </Modal>
    </div>
  );
};

import { useState, useEffect, useCallback } from 'react';
import Skeleton from 'react-loading-skeleton';
import 'react-loading-skeleton/dist/skeleton.css';
import Modal from '../../../components/common/Modal';
import toast from 'react-hot-toast';
import Swal from 'sweetalert2';
import cajaService from '../../../services/cajaNotaVenta.service';
import { useAuth } from '../../../hooks/useAuth';
import { AperturaCajaForm } from '../../CajaBoleteria/components/AperturaCajaForm';
import { CierreCajaForm } from '../../CajaBoleteria/components/CierreCajaForm';

/**
 * Módulo de Cajas para Notas de Venta.
 * Replica CajaPage.jsx con las mismas funciones:
 * listado, apertura, cierre, comprobante, detalle, editar, arqueo, solicitudes.
 */
export const CajaNotaVentaContent = () => {
  const { user } = useAuth();
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [totalRecords, setTotalRecords] = useState(0);
  const [openCaja, setOpenCaja] = useState(null);

  // Modales
  const [showApertura, setShowApertura] = useState(false);
  const [showCierre, setShowCierre] = useState(false);
  const [cajaParaCierre, setCajaParaCierre] = useState(null);
  const [showDetalle, setShowDetalle] = useState(false);
  const [detalleData, setDetalleData] = useState([]);
  const [detalleLoading, setDetalleLoading] = useState(false);
  const [detalleCajaId, setDetalleCajaId] = useState(null);
  const [detalleCajaNum, setDetalleCajaNum] = useState('');

  // Filtros y paginación
  const [filters, setFilters] = useState({ desde: '', hasta: '', estado: '' });
  const [pagination, setPagination] = useState({ pageIndex: 0, pageSize: 25 });

  // ─── LISTADO ────────────────────────────────────────────────────────────
  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const params = { ...filters, page: pagination.pageIndex + 1, limit: pagination.pageSize };
      const res = await cajaService.listadoCaja(params);
      if (res.success) {
        setData(res.data || []);
        setTotalRecords(res.total || 0);
      }
    } catch (err) {
      toast.error('Error al cargar cajas');
    } finally {
      setLoading(false);
    }
  }, [filters, pagination]);

  useEffect(() => { loadData(); }, [loadData]);

  // ─── VALIDAR CAJA ABIERTA ──────────────────────────────────────────────
  useEffect(() => {
    cajaService.validarCaja().then(res => {
      if (res.success) setOpenCaja(res.data);
      else setOpenCaja(null);
    }).catch(() => setOpenCaja(null));
  }, []);

  // ─── APERTURA DE CAJA ────────────────────────────────────────────────
  const handleApertura = async (formData) => {
    const res = await cajaService.insertarAperturaCaja(formData);
    if (res.success) { toast.success('Caja aperturada correctamente'); loadData(); setShowApertura(false); }
    else toast.error(res.message || 'Error al aperturar');
  };

  // ─── CIERRE DE CAJA ────────────────────────────────────────────────────
  const openCierreModal = (caja) => {
    if (!caja || caja.estado_caja === 'CERRADA') { toast.error('La caja ya está cerrada'); return; }
    setCajaParaCierre(caja);
    setShowCierre(true);
  };

  const handleCierreSubmit = async (formData) => {
    const res = await cajaService.cerrarCaja({ ...formData, id_caja: cajaParaCierre.id_caja });
    if (res.success) {
      let msg = 'Caja cerrada correctamente';
      if (res.estado_cuadre === 'CUADRADO') msg += '. Caja cuadrada.';
      else if (res.estado_cuadre === 'FALTANTE') msg += `. Faltante de $${res.valor_diferencia}`;
      else if (res.estado_cuadre === 'SOBRANTE') msg += `. Sobrante de $${res.valor_diferencia}`;
      toast.success(msg);
      loadData();
      setShowCierre(false);
    } else toast.error(res.message || 'Error al cerrar');
  };

  // ─── INFO COMPROBANTE ──────────────────────────────────────────────────
  const handleInfoComprobante = async (row) => {
    const { value: form, isDismissed } = await Swal.fire({
      title: 'Información de Comprobante',
      html: `
        <div style="text-align:left">
          <label style="display:block;font-weight:bold;font-size:12px;margin-bottom:4px">N° Comprobante</label>
          <input id="swal-num" style="width:100%;padding:6px 10px;font-size:13px;border:1px solid #d1d5db;border-radius:6px" />
          <label style="display:block;font-weight:bold;font-size:12px;margin:8px 0 4px">Banco</label>
          <input id="swal-banco" style="width:100%;padding:6px 10px;font-size:13px;border:1px solid #d1d5db;border-radius:6px" />
        </div>`,
      showCancelButton: true,
      confirmButtonText: 'Guardar',
      preConfirm: () => ({
        id_caja: row.id_caja,
        numero_comprobante: document.getElementById('swal-num')?.value || '',
        banco: document.getElementById('swal-banco')?.value || ''
      })
    });
    if (!form || isDismissed) return;
    const res = await cajaService.guardarInfoComprobante(form);
    if (res.success) { toast.success('Comprobante guardado'); loadData(); }
    else toast.error(res.message || 'Error');
  };

  // ─── DETALLE DE CAJA ───────────────────────────────────────────────────
  const handleVerDetalle = async (row) => {
    setDetalleCajaId(row.id_caja);
    setDetalleCajaNum(row.numero_caja);
    setShowDetalle(true);
    setDetalleLoading(true);
    try {
      const res = await cajaService.listadoDetalleCaja(row.id_caja);
      setDetalleData(res.data || []);
    } catch {
      toast.error('Error al cargar detalle');
      setDetalleData([]);
    } finally {
      setDetalleLoading(false);
    }
  };

  // ─── EDITAR CAJA ───────────────────────────────────────────────────────
  const handleEditar = async (row) => {
    if (row.estado_caja === 'CERRADA') {
      toast.error('No se puede editar una caja cerrada');
      return;
    }
    const { value: form, isDismissed } = await Swal.fire({
      title: `Editar Caja #${row.numero_caja}`,
      html: `
        <div style="text-align:left">
          <label style="display:block;font-weight:bold;font-size:12px;margin-bottom:4px">Sucursal</label>
          <input id="edit-sucursal" value="${row.nombre_sucursal || ''}" style="width:100%;padding:6px 10px;font-size:13px;border:1px solid #d1d5db;border-radius:6px" />
          <label style="display:block;font-weight:bold;font-size:12px;margin:8px 0 4px">Usuario</label>
          <input id="edit-usuario" value="${row.usuario || ''}" style="width:100%;padding:6px 10px;font-size:13px;border:1px solid #d1d5db;border-radius:6px" />
        </div>`,
      showCancelButton: true,
      confirmButtonText: 'Guardar',
      preConfirm: () => ({
        id_caja: row.id_caja,
        nombre_sucursal: document.getElementById('edit-sucursal')?.value || '',
        usuario: document.getElementById('edit-usuario')?.value || ''
      })
    });
    if (!form || isDismissed) return;
    const res = await cajaService.editarCaja(form);
    if (res.success) { toast.success('Caja editada correctamente'); loadData(); }
    else toast.error(res.message || 'Error al editar');
  };

  // ─── ARQUEO PDF ────────────────────────────────────────────────────────
  const handleArqueo = async (row) => {
    try {
      const res = await cajaService.arqueoCajaPdf(row.id_caja);
      if (res.success && res.url) {
        window.open(res.url, '_blank');
      } else {
        toast.error(res.message || 'No se pudo generar el arqueo');
      }
    } catch {
      toast.error('Error al generar arqueo');
    }
  };

  // ─── COMPROBANTES ─────────────────────────────────────────────────────
  const handleComprobantes = (row) => {
    window.open(`/caja_nota_venta/reportecomprobantefacturasxcaja?idcaja=${row.id_caja}`, '_blank');
  };

  // ─── SOLICITUD EDICIÓN ─────────────────────────────────────────────────
  const handleSolicitudEdicion = async (row) => {
    const confirm = await Swal.fire({
      title: '¿Enviar solicitud de edición?',
      text: `Se enviará una solicitud para editar la caja #${row.numero_caja}`,
      icon: 'question',
      showCancelButton: true,
      confirmButtonText: 'Sí, enviar',
      cancelButtonText: 'Cancelar'
    });
    if (!confirm.isConfirmed) return;
    const res = await cajaService.enviarSolicitudEdicion(row.id_caja);
    if (res.success) toast.success('Solicitud enviada correctamente');
    else toast.error(res.message || 'Error al enviar solicitud');
  };

  // ─── APROBAR SOLICITUD ─────────────────────────────────────────────────
  const handleAprobarSolicitud = async (row) => {
    const confirm = await Swal.fire({
      title: '¿Aprobar solicitud?',
      text: `Se aprobará la solicitud de edición de la caja #${row.numero_caja}`,
      icon: 'question',
      showCancelButton: true,
      confirmButtonText: 'Sí, aprobar',
      cancelButtonText: 'Cancelar'
    });
    if (!confirm.isConfirmed) return;
    const res = await cajaService.aprobarSolicitud(row.id_caja);
    if (res.success) { toast.success('Solicitud aprobada'); loadData(); }
    else toast.error(res.message || 'Error al aprobar');
  };

  // ─── PAGINACIÓN ────────────────────────────────────────────────────────
  const totalPages = Math.max(1, Math.ceil(totalRecords / pagination.pageSize));
  const canPrev = pagination.pageIndex > 0;
  const canNext = pagination.pageIndex < totalPages - 1;

  const handlePrev = () => setPagination(p => ({ ...p, pageIndex: Math.max(0, p.pageIndex - 1) }));
  const handleNext = () => setPagination(p => ({ ...p, pageIndex: p.pageIndex + 1 }));

  // ─── ESTADO BADGE ──────────────────────────────────────────────────────
  const renderEstado = (val) => {
    const ap = val === 'APERTURADA';
    return (
      <span className={`px-2 py-0.5 rounded-full text-[8px] font-black uppercase ${ap ? 'bg-emerald-50 text-emerald-700' : 'bg-rose-50 text-rose-700'}`}>
        {val || 'CERRADA'}
      </span>
    );
  };

  return (
    <div className="flex flex-col flex-1 min-h-0">
      {/* ── FILTROS ──────────────────────────────────────────────────────── */}
      <div className="px-4 py-2 border-b border-slate-100 flex flex-wrap items-center gap-3 bg-white">
        <div className="flex items-center gap-1.5 text-slate-400">
          <i className="fas fa-filter text-[10px]"></i>
          <span className="text-[9px] font-black uppercase tracking-tighter">Filtros:</span>
        </div>
        <input type="date" value={filters.desde}
          onChange={e => setFilters(p => ({ ...p, desde: e.target.value }))}
          className="h-8 px-2 text-[10px] border border-slate-200 rounded-lg font-bold text-slate-700 w-[160px]" />
        <input type="date" value={filters.hasta}
          onChange={e => setFilters(p => ({ ...p, hasta: e.target.value }))}
          className="h-8 px-2 text-[10px] border border-slate-200 rounded-lg font-bold text-slate-700 w-[160px]" />
        <select value={filters.estado}
          onChange={e => setFilters(p => ({ ...p, estado: e.target.value }))}
          className="h-8 px-2 text-[10px] border border-slate-200 rounded-lg font-bold text-slate-700 w-[150px]">
          <option value="">Estado: TODOS</option>
          <option value="APERTURADA">APERTURADA</option>
          <option value="CERRADA">CERRADA</option>
        </select>
        <button onClick={() => setPagination(p => ({ ...p, pageIndex: 0 }))} disabled={loading}
          className="h-8 px-4 bg-slate-800 hover:bg-slate-900 text-white text-[10px] font-black rounded-lg flex items-center gap-2 active:scale-95 disabled:opacity-70 uppercase tracking-widest">
          <i className="fas fa-search"></i> BUSCAR
        </button>
        <button onClick={() => { setFilters({ desde: '', hasta: '', estado: '' }); setPagination(p => ({ ...p, pageIndex: 0 })); }}
          className="h-8 w-8 flex items-center justify-center text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg" title="Limpiar">
          <i className="fas fa-eraser text-xs"></i>
        </button>
        {openCaja && (
          <div className="ml-auto flex items-center gap-2">
            <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">
              <i className="fas fa-lock-open mr-1"></i> Caja Abierta: #{openCaja.numero_caja || openCaja.id_caja}
            </span>
          </div>
        )}
        <button onClick={() => setShowApertura(true)}
            className="h-8 px-3 bg-emerald-100 hover:bg-emerald-200 text-emerald-700 text-[10px] font-black rounded-lg flex items-center gap-2 active:scale-95 uppercase">
            <i className="fas fa-cash-register"></i> Nueva Apertura
          </button>
      </div>

      {/* ── GRID ─────────────────────────────────────────────────────────── */}
      <div className="flex-1 bg-white flex flex-col overflow-hidden min-h-0">
        <div className="flex-1 overflow-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 sticky top-0 z-[1] border-b border-slate-200">
              <tr>
                <th className="py-2 px-4 text-[9px] font-black text-slate-400 uppercase tracking-widest w-10 text-center">#</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest">N° CAJA</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest">FECHA</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest">SUCURSAL</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest">USUARIO</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest text-center">ESTADO</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest text-right">($)APERTURA</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest text-right">($)CIERRE</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest">COMPROBANTE</th>
                <th className="py-2 px-3 text-[9px] font-black text-slate-500 uppercase tracking-widest">BANCO</th>
                <th className="py-2 px-4 text-[9px] font-black text-slate-500 uppercase tracking-widest text-center">ACCIONES</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {loading ? (
                Array(8).fill(0).map((_, i) => (
                  <tr key={i}>
                    {Array(11).fill(0).map((_, j) => <td key={j} className="py-2 px-3"><Skeleton height={12} /></td>)}
                  </tr>
                ))
              ) : data.length > 0 ? (
                data.map((row, i) => (
                  <tr key={row.id_caja || i} className="group hover:bg-indigo-50/30 transition-all">
                    <td className="py-2 px-4 text-slate-400 font-mono text-[9px] text-center">{pagination.pageIndex * pagination.pageSize + i + 1}</td>
                    <td className="py-2 px-3 text-blue-600 font-bold text-[11px] font-mono">{row.numero_caja || '-'}</td>
                    <td className="py-2 px-3 text-slate-600 text-[10px]">{row.fecha_caja ? row.fecha_caja.split(' ')[0] : '-'}</td>
                    <td className="py-2 px-3 text-slate-600 text-[10px]">{row.nombre_sucursal || '-'}</td>
                    <td className="py-2 px-3 text-slate-600 text-[10px]">{row.usuario || '-'}</td>
                    <td className="py-2 px-3 text-center">{renderEstado(row.estado_caja)}</td>
                    <td className="py-2 px-3 text-right font-mono font-semibold text-[11px] text-slate-800">
                      ${parseFloat(row.apertura_total_caja || 0).toFixed(2)}
                    </td>
                    <td className="py-2 px-3 text-right font-mono font-semibold text-[11px] text-slate-800">
                      {row.cierre_total_caja ? `$${parseFloat(row.cierre_total_caja).toFixed(2)}` : '-'}
                    </td>
                    <td className="py-2 px-3 text-slate-600 text-[10px]">{row.numero_comprobante_cierre || '-'}</td>
                    <td className="py-2 px-3 text-slate-600 text-[10px]">{row.banco_cierre || '-'}</td>
                    <td className="py-2 px-4 text-center">
                      <div className="flex items-center justify-center gap-1">
                        {[
                          {a:() => handleInfoComprobante(row), i:'fa-vote-yea', c:'text-indigo-500 hover:bg-indigo-50', t:'Info Comprobante'},
                          {a:() => handleArqueo(row), i:'fa-file-pdf', c:'text-red-500 hover:bg-red-50', t:'Arqueo'},
                          {a:() => handleComprobantes(row), i:'fa-file-invoice', c:'text-red-500 hover:bg-red-50', t:'Comprobantes'},
                          {a:() => handleEditar(row), i:'fa-edit', c:'text-amber-500 hover:bg-amber-50', t:'Editar Caja'},
                          row.estado_caja === 'APERTURADA' ? {a:() => openCierreModal(row), i:'fa-sign-out-alt', c:'text-blue-500 hover:bg-blue-50', t:'Cerrar Caja'} : null,
                          row.estado_caja === 'CERRADA' ? {a:() => handleSolicitudEdicion(row), i:'fa-share-square', c:'text-purple-500 hover:bg-purple-50', t:'Solicitud'} : null,
                          row.estado_solicitud === 'PENDIENTE' ? {a:() => handleAprobarSolicitud(row), i:'fa-print', c:'text-slate-500 hover:bg-slate-50', t:'Aprobar Solicitud'} : null,
                        ].filter(Boolean).map((b, idx) => (
                          <button key={idx} onClick={b.a} title={b.t}
                            className={`w-7 h-7 rounded ${b.c} flex items-center justify-center transition-colors`}>
                            <i className={`fas ${b.i} text-[10px]`}></i>
                          </button>
                        ))}
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={11} className="py-12 text-center">
                    <div className="flex flex-col items-center gap-2">
                      <i className="fas fa-folder-open text-xl text-slate-200"></i>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sin registros de cajas</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Paginador */}
        <div className="border-t border-slate-200 bg-slate-50 px-4 py-2 flex items-center justify-between shrink-0">
          <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
            {totalRecords > 0
              ? `${pagination.pageIndex * pagination.pageSize + 1}–${Math.min((pagination.pageIndex + 1) * pagination.pageSize, totalRecords)} DE ${totalRecords}`
              : '0 REGISTROS'}
          </span>
          <div className="flex items-center gap-1">
            <button onClick={handlePrev} disabled={!canPrev || loading}
              className="w-7 h-7 rounded-lg flex items-center justify-center border border-slate-200 text-slate-600 hover:bg-white disabled:opacity-30 transition-all active:scale-90">
              <i className="fas fa-chevron-left text-[8px]"></i>
            </button>
            <div className="px-3 h-7 flex items-center justify-center bg-white rounded-lg border border-slate-200 text-[9px] font-black text-slate-700 min-w-[80px] uppercase tracking-tighter">
              PÁG {pagination.pageIndex + 1} / {totalPages || 1}
            </div>
            <button onClick={handleNext} disabled={!canNext || loading}
              className="w-7 h-7 rounded-lg flex items-center justify-center border border-slate-200 text-slate-600 hover:bg-white disabled:opacity-30 transition-all active:scale-90">
              <i className="fas fa-chevron-right text-[8px]"></i>
            </button>
          </div>
        </div>
      </div>

      {/* ── MODAL: Apertura de Caja ──────────────────────────────── */}
      {showApertura && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[85vh]">
            <div className="flex-1 overflow-y-auto p-6">
              <AperturaCajaForm
                onSubmit={handleApertura}
                onCancel={() => setShowApertura(false)}
              />
            </div>
          </div>
        </div>
      )}

      {/* ── MODAL: Cierre de Caja ──────────────────────────────── */}
      {showCierre && cajaParaCierre && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex-1 overflow-y-auto p-6">
              <CierreCajaForm
                cajaActual={cajaParaCierre}
                onSubmit={handleCierreSubmit}
                onCancel={() => setShowCierre(false)}
              />
            </div>
          </div>
        </div>
      )}

      {/* ── MODAL: Detalle de Caja ──────────────────────────────── */}
      {showDetalle && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col max-h-[80vh]">
            <div className="bg-slate-800 px-6 py-4 flex items-center justify-between flex-shrink-0">
              <h2 className="text-white text-lg font-bold flex items-center gap-2">
                <i className="fas fa-list text-blue-400"></i> DETALLE DE CAJA #{detalleCajaNum}
              </h2>
              <button onClick={() => { setShowDetalle(false); setDetalleData([]); }}
                className="text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-6">
              {detalleLoading ? (
                <div className="flex items-center justify-center py-12">
                  <i className="fas fa-spinner fa-spin text-2xl text-blue-500 mr-3"></i>
                  <span className="text-slate-500 font-medium">Cargando detalle...</span>
                </div>
              ) : detalleData.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                  <i className="fas fa-inbox text-4xl mb-3"></i>
                  <p className="font-medium">No hay movimientos en esta caja.</p>
                </div>
              ) : (
                <div className="overflow-x-auto rounded-lg border border-slate-200">
                  <table className="w-full text-sm">
                    <thead className="bg-slate-50 border-b border-slate-200">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase">#</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase">TIPO</th>
                        <th className="px-4 py-3 text-right text-xs font-semibold text-slate-600 uppercase">MONTO</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase">OBSERVACIÓN</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase">SOCIO</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase">DOCUMENTO</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {detalleData.map((d, i) => (
                        <tr key={d.id_caja_detalle || i} className="hover:bg-slate-50 transition-colors">
                          <td className="px-4 py-3 text-slate-500 font-mono text-xs">{i + 1}</td>
                          <td className="px-4 py-3 text-xs">
                            <span className={`px-2 py-0.5 rounded-full font-medium ${
                              d.tipo_caja_detalle === 1 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                            }`}>
                              {d.tipo_caja_detalle === 1 ? 'INGRESO' : 'EGRESO'}
                            </span>
                          </td>
                          <td className={`px-4 py-3 text-right font-mono font-semibold text-xs ${
                            d.tipo_caja_detalle === 1 ? 'text-green-700' : 'text-red-700'
                          }`}>
                            ${parseFloat(d.monto_caja_detalle || 0).toFixed(2)}
                          </td>
                          <td className="px-4 py-3 text-slate-600 text-xs">{d.observacion_caja_detalle || '-'}</td>
                          <td className="px-4 py-3 text-slate-600 text-xs">{d.nombre_socio || '-'}</td>
                          <td className="px-4 py-3 text-slate-600 text-xs">{d.numero_documento || '-'}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
            <div className="flex-shrink-0 border-t border-slate-100 px-6 py-3 flex justify-end">
              <button onClick={() => { setShowDetalle(false); setDetalleData([]); }}
                className="px-5 py-2 bg-slate-700 hover:bg-slate-800 text-white rounded-md font-medium transition-colors text-sm">
                Cerrar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { useState, useEffect, useRef } from 'react';
import toast from 'react-hot-toast';
import { api } from '../../../config/axios';
import { getFormasPago } from '../../../services/formapago.service';
import { GuiaService } from '../../../services/guia.service';

/**
 * Modal para cobrar una factura asociada a una guía.
 * Recrea la funcionalidad de CobrarFactura de ExtJS.
 */
export const CobrarFacturaModal = ({ guia, onClose, onSuccess, isNotaVenta = false, facturaDataPreloaded = null, cajaId = null }) => {
  const [loadingInit, setLoadingInit] = useState(true);
  const [saving, setSaving] = useState(false);
  const [facturaData, setFacturaData] = useState(null);
  const [formasPago, setFormasPago] = useState([]);

  const [formData, setFormData] = useState({
    monto: '',
    idformapago: '',
    fecha: new Date().toISOString().split('T')[0],
    concepto: '',
    observacion: '',
    archivocomprobante: ''
  });

  const fileInputRef = useRef(null);
  const fetchedRef = useRef(false);

  useEffect(() => {
    // Evitar doble petición en React StrictMode
    if (fetchedRef.current) return;
    fetchedRef.current = true;

    const init = async () => {
      try {
        // 1. Obtener formas de pago
        const fPagosRes = await getFormasPago({ limite: 1000 });
        if (fPagosRes.success && fPagosRes.data) {
          setFormasPago(fPagosRes.data);
        }

        if (isNotaVenta) {
          // Para Notas de Venta, no hay factura. Cobramos el total_guia directamente.
          const { GuiaNotaVentaService } = await import('../../../services/guiaNotaVenta.service');

          // Obtenemos los detalles del remitente y el total de la guía
          const infoRes = await GuiaNotaVentaService.informacionGuia(guia.id_guia);
          if (infoRes) {
            let gInfo = infoRes.data || infoRes;
            if (Array.isArray(gInfo)) gInfo = gInfo[0];

            if (!gInfo) {
              toast.error('La guía no contiene información válida');
              onClose();
              return;
            }
            const restante = parseFloat(gInfo.por_cobrar !== undefined ? gInfo.por_cobrar : (gInfo.total_guia || 0));

            if (restante <= 0) {
              toast.success('La nota de venta ya se encuentra cobrada en su totalidad');
              onClose();
              return;
            }

            setFacturaData({
              id_factura: null,
              id_fkcliente_factura: gInfo.id_fkcliente_remitente,
              punto_emision_sucursal: 'NV',
              punto_emision_factura: '000',
              numero_factura: gInfo.numero_guia_final || gInfo.numero_guia || gInfo.id_guia,
              total_factura: restante.toFixed(2)
            });
            setFormData(prev => ({
              ...prev,
              monto: restante.toFixed(2)
            }));
          } else {
            toast.error('No se pudo obtener la información de la Nota de Venta');
            onClose();
          }
        } else {
          // 2. Obtener datos de la factura a cobrar
          // Si ya tenemos datos precargados desde handleCharge, no duplicamos la petición
          let fData = null;
          if (facturaDataPreloaded) {
            fData = facturaDataPreloaded;
          } else {
            const factDataRes = await api.get(`/factura/autorizadofacturaxguia?id_guia=${guia.id_guia}`);
            const facturas = factDataRes?.data?.data || [];
            if (facturas.length > 0) {
              fData = facturas[0];
            }
          }

          if (fData) {

            // Obtener suma ya cobrada
            const sumRes = await api.get(`/factura/facturaidguicobradasuma?id_guia=${guia.id_guia}`);
            const cobrado = (sumRes && sumRes.success && sumRes.data) ? parseFloat(sumRes.data) : 0;

            const totalAFacturar = parseFloat(fData.total_factura || 0);
            const restante = totalAFacturar - cobrado;

            if (restante <= 0) {
              toast.success('La guía ya se encuentra cobrada en su totalidad');
              onClose();
              return;
            }

            setFacturaData({
              ...fData,
              total_factura: restante.toFixed(2)
            });
            setFormData(prev => ({
              ...prev,
              monto: restante.toFixed(2)
            }));
          } else {
            toast.error('Esta guía no tiene una factura autorizada para cobrar. Debe facturar la guía primero.');
            onClose();
          }
        }
      } catch (err) {
        console.error('Error inicializando modal de cobro', err);
        toast.error('Error al cargar datos de factura');
        onClose();
      } finally {
        setLoadingInit(false);
      }
    };
    init();
  }, [guia.id_guia, onClose]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, archivocomprobante: reader.result }));
      };
      reader.readAsDataURL(file);
    } else {
      setFormData(prev => ({ ...prev, archivocomprobante: '' }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.monto || !formData.idformapago || !formData.fecha || !formData.concepto) {
      toast.error('Por favor complete todos los campos obligatorios');
      return;
    }

    const montoVal = parseFloat(formData.monto);
    if (montoVal <= 0 || montoVal > parseFloat(facturaData.total_factura)) {
      toast.error(`El monto debe ser mayor a 0 y no puede exceder el total a cobrar ($${facturaData.total_factura})`);
      return;
    }

    setSaving(true);
    try {
      const payload = {
        id: "",
        fecha: formData.fecha,
        concepto: formData.concepto,
        monto: montoVal,
        idcliente: facturaData.id_fkcliente_factura,
        idfactura: facturaData.id_factura,
        estado: 'COBRADA',
        idformapago: formData.idformapago,
        tipo: isNotaVenta ? 2 : 1, // 2 para guía directa/nota de venta, 1 para factura
        observacion: formData.observacion || ' ',
        id_guia: guia.id_guia,
        destino_guia: guia.destino_guia || guia.destino || '',
        archivocomprobante: formData.archivocomprobante,
        id_caja_global: cajaId // ← se envía para que el backend sepa qué caja usar
      };

      let res;
      if (isNotaVenta) {
        const { GuiaNotaVentaService } = await import('../../../services/guiaNotaVenta.service');
        res = await GuiaNotaVentaService.insertarComprobante(payload);
      } else {
        res = await api.post('/comprobantecobro/comprobanteCobroInsertarActualizar', payload);
      }

      const respuesta = isNotaVenta ? res : (res?.data || res);

      // Si el backend indica que no hay caja aperturada (tipo === 3)
      if (respuesta && respuesta.tipo === 3) {
        toast.error(respuesta?.message || 'No hay una caja aperturada. Debe aperturar una caja de notas de venta primero.');
        return;
      }

      if (respuesta && respuesta.success) {
        toast.success('Cobro registrado correctamente');
        if (onSuccess) onSuccess();
        onClose();
      } else {
        toast.error(respuesta?.message || (typeof respuesta?.data === 'string' ? respuesta.data : 'Error al registrar el cobro'));
      }
    } catch (err) {
      console.error(err);
      toast.error('Ocurrió un error al guardar el comprobante');
    } finally {
      setSaving(false);
    }
  };

  if (loadingInit) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
        <div className="bg-white rounded-xl shadow-2xl p-8 flex flex-col items-center">
          <i className="fas fa-spinner fa-spin text-3xl text-blue-600 mb-4"></i>
          <p className="text-slate-600 font-medium">Cargando información de factura...</p>
        </div>
      </div>
    );
  }

  if (!facturaData) return null;

  const numFactura = String(facturaData.numero_factura).padStart(9, '0');
  const nombreFactura = `${facturaData.punto_emision_sucursal}-${facturaData.punto_emision_factura}-${numFactura}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col">
        {/* Header */}
        <div className="bg-slate-800 px-6 py-4 flex items-center justify-between">
          <h2 className="text-white text-lg font-bold flex items-center gap-2">
            <i className="fas fa-money-bill-wave text-green-400"></i> REALIZAR COBRO
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        {/* Body */}
        <form onSubmit={handleSubmit} className="p-6 flex flex-col gap-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50 p-4 rounded-lg border border-slate-200">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">{isNotaVenta ? 'Nota de Venta' : 'Factura'}</label>
              <div className="text-slate-900 font-medium px-3 py-2 bg-white border border-slate-200 rounded-md">
                {isNotaVenta ? `Guía #${facturaData.numero_factura}` : nombreFactura}
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Total a cobrar</label>
              <div className="text-green-700 font-bold px-3 py-2 bg-green-50 border border-green-200 rounded-md">
                ${facturaData.total_factura}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Monto USD <span className="text-red-500">*</span></label>
              <input
                type="number"
                step="0.01"
                min="0.1"
                max={facturaData.total_factura}
                name="monto"
                value={formData.monto}
                onChange={handleInputChange}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Forma Pago <span className="text-red-500">*</span></label>
              <select
                name="idformapago"
                value={formData.idformapago}
                onChange={handleInputChange}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                required
              >
                <option value="">Seleccionar</option>
                {formasPago.map(fp => (
                  <option key={fp.id_forma_pago} value={fp.id_forma_pago}>
                    {fp.nombre_forma_pago}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Fecha <span className="text-red-500">*</span></label>
              <input
                type="date"
                name="fecha"
                value={formData.fecha}
                onChange={handleInputChange}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Nº Depósito / Transferencia / Otros... <span className="text-red-500">*</span></label>
            <input
              type="text"
              name="concepto"
              value={formData.concepto}
              onChange={handleInputChange}
              className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 uppercase"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Observación</label>
            <input
              type="text"
              name="observacion"
              value={formData.observacion}
              onChange={handleInputChange}
              className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Imagen (Opcional)</label>
            <input
              type="file"
              accept="image/*"
              onChange={handleFileChange}
              ref={fileInputRef}
              className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          {/* Footer actions */}
          <div className="flex items-center justify-end gap-3 mt-4 pt-4 border-t border-slate-100">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-md font-medium transition-colors"
              disabled={saving}
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="px-6 py-2 bg-green-600 hover:bg-green-700 text-white rounded-md font-medium shadow-sm transition-colors flex items-center gap-2"
              disabled={saving}
            >
              {saving ? (
                <><i className="fas fa-spinner fa-spin"></i> Guardando...</>
              ) : (
                <><i className="fas fa-save"></i> Guardar</>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import { useState, useEffect, useRef } from 'react';
import toast from 'react-hot-toast';
import { GuiaService } from '../../../services/guia.service';
import { api } from '../../../config/axios';
import { useAuth } from '../../../hooks/useAuth';

/**
 * Modal de cobros realizados por guía.
 * Incluye anulación de comprobantes, replicando CobrosRealizados + AnularComprobanteCobro de ExtJS.
 */
export const CobrosRealizadosModal = ({ guia, onClose, onUpdate, isNotaVenta = false }) => {
  const [cobros, setCobros] = useState([]);
  const [loading, setLoading] = useState(true);
  const fetchedRef = useRef(false);

  const [anularModal, setAnularModal] = useState({ open: false, cobro: null });
  const [anularGuiaModal, setAnularGuiaModal] = useState({ open: false });
  const [motivoAnulacion, setMotivoAnulacion] = useState('');
  const [anulando, setAnulando] = useState(false);
  const anulandoRef = useRef(false);

  const { user } = useAuth();

  const cargarCobros = async () => {
    setLoading(true);
    try {
      let res;
      if (isNotaVenta) {
        const { GuiaNotaVentaService } = await import('../../../services/guiaNotaVenta.service');
        res = await GuiaNotaVentaService.getComprobantesPorCaja(guia.id_guia);
      } else {
        res = await GuiaService.getComprobantesPorCaja(guia.id_guia);
      }

      if (res && res.success) {
        setCobros(Array.isArray(res.data) ? res.data : []);
      } else {
        setCobros([]);
      }
    } catch (err) {
      console.error(err);
      toast.error('No se pudieron cargar los cobros');
      setCobros([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (fetchedRef.current) return;
    fetchedRef.current = true;
    cargarCobros();
  }, [guia.id_guia]);

  const totalCobrado = cobros.reduce((sum, c) => {
    if (c.estado_comprobante_cobro === 'COBRADA') {
      return sum + parseFloat(c.monto_comprobante_cobro || 0);
    }
    return sum;
  }, 0);

  const formatFecha = (fecha) => {
    if (!fecha) return '-';
    try {
      return new Date(fecha).toLocaleDateString('es-EC', {
        day: '2-digit', month: '2-digit', year: 'numeric'
      });
    } catch {
      return fecha;
    }
  };

  const abrirAnulacion = (cobro) => {
    if (cobro.estado_comprobante_cobro === 'ANULADA') {
      toast.error('Este comprobante ya se encuentra anulado');
      return;
    }
    setMotivoAnulacion('');
    setAnularModal({ open: true, cobro });
  };

  const confirmarAnulacion = async () => {
    if (anulandoRef.current) return;
    if (!motivoAnulacion.trim()) {
      toast.error('Debe ingresar el motivo de anulación');
      return;
    }
    anulandoRef.current = true;
    setAnulando(true);
    try {
      let res;
      if (isNotaVenta) {
        const { GuiaNotaVentaService } = await import('../../../services/guiaNotaVenta.service');
        res = await GuiaNotaVentaService.anularComprobante(anularModal.cobro.id_comprobante_cobro, motivoAnulacion.toUpperCase());
      } else {
        res = await api.post('/comprobantecobro/anularComprobante', {
          id: anularModal.cobro.id_comprobante_cobro,
          motivoAnulacion: motivoAnulacion.toUpperCase()
        });
      }

      const respuesta = isNotaVenta ? res : (res?.data || res);

      if (respuesta && respuesta.success) {
        toast.success('Comprobante anulado correctamente');
        setAnularModal({ open: false, cobro: null });
        // Reload cobros
        fetchedRef.current = false;
        await cargarCobros();
        fetchedRef.current = true;
        if (onUpdate) onUpdate();
      } else {
        toast.error(respuesta?.message || (typeof respuesta?.data === 'string' ? respuesta.data : 'No se pudo anular el comprobante'));
      }
    } catch (err) {
      console.error(err);
      toast.error('Error al anular el comprobante');
    } finally {
      anulandoRef.current = false;
      setAnulando(false);
    }
  };

  const confirmarAnulacionGuia = async () => {
    if (anulandoRef.current) return;
    if (!motivoAnulacion.trim()) {
      toast.error('Debe ingresar el motivo de anulación de la guía');
      return;
    }
    anulandoRef.current = true;
    setAnulando(true);
    try {
      const idUsuario = user?.id_usuario || 0;
      // Replicando onanularTodoGuia -> Anulacion -> anularadministrador
      let res;
      if (isNotaVenta) {
        const { GuiaNotaVentaService } = await import('../../../services/guiaNotaVenta.service');
        res = await GuiaNotaVentaService.anularAdministrador(guia.id_guia, idUsuario, motivoAnulacion.toUpperCase());
      } else {
        res = await GuiaService.anularAdministrador(guia.id_guia, idUsuario, motivoAnulacion.toUpperCase());
      }

      if (res && res.success) {
        toast.success('Guía anulada correctamente');
        setAnularGuiaModal({ open: false });
        if (onUpdate) onUpdate();
        onClose(); // Cerrar el modal principal porque la guía ya fue anulada
      } else {
        toast.error(res?.message || 'No se pudo anular la guía');
      }
    } catch (err) {
      console.error(err);
      toast.error('Error al anular la guía completa');
    } finally {
      anulandoRef.current = false;
      setAnulando(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="bg-slate-800 px-6 py-4 flex items-center justify-between flex-shrink-0">
          <div>
            <h2 className="text-white text-lg font-bold flex items-center gap-2">
              <i className="fas fa-receipt text-blue-400"></i> COBROS REALIZADOS
            </h2>
            <p className="text-slate-400 text-xs mt-0.5">
              Guía <strong className="text-slate-300">
                #{guia.numero_guia_final || guia.numero_guia || guia.id_guia}
              </strong>
            </p>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => { setMotivoAnulacion(''); setAnularGuiaModal({ open: true }); }}
              className="px-4 py-1.5 bg-red-600/20 text-red-300 hover:bg-red-600 hover:text-white rounded-md text-sm font-semibold transition-colors flex items-center gap-2 border border-red-500/30"
              title="Anular Toda la Guía"
            >
              <i className="fas fa-ban"></i> Anular Guía
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors ml-2">
              <i className="fas fa-times text-xl"></i>
            </button>
          </div>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-6">
          {loading && (
            <div className="flex items-center justify-center py-12 text-slate-500">
              <i className="fas fa-spinner fa-spin text-2xl mr-3 text-blue-500"></i>
              <span className="font-medium">Cargando cobros...</span>
            </div>
          )}

          {!loading && cobros.length === 0 && (
            <div className="flex flex-col items-center justify-center py-12 text-slate-400">
              <i className="fas fa-inbox text-4xl mb-3"></i>
              <p className="font-medium">No se encontraron cobros para esta guía.</p>
            </div>
          )}

          {!loading && cobros.length > 0 && (
            <div className="overflow-x-auto rounded-lg border border-slate-200">
              <table className="w-full text-sm">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase tracking-wide">#</th>
                    <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase tracking-wide">Fecha</th>
                    <th className="px-4 py-3 text-right text-xs font-semibold text-slate-600 uppercase tracking-wide">Monto</th>
                    <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase tracking-wide">Forma de Pago</th>
                    <th className="px-4 py-3 text-center text-xs font-semibold text-slate-600 uppercase tracking-wide">Estado</th>
                    <th className="px-4 py-3 text-left text-xs font-semibold text-slate-600 uppercase tracking-wide">Observación</th>
                    <th className="px-4 py-3 text-center text-xs font-semibold text-slate-600 uppercase tracking-wide">Acción</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {cobros.map((c, i) => {
                    const esAnulada = c.estado_comprobante_cobro === 'ANULADA';
                    return (
                      <tr key={c.id_comprobante_cobro || i}
                        className={`transition-colors ${esAnulada ? 'bg-red-50/50' : 'hover:bg-slate-50'}`}>
                        <td className="px-4 py-3 text-slate-500 font-mono text-xs">{i + 1}</td>
                        <td className="px-4 py-3 text-slate-700">
                          {formatFecha(c.fecha_emision_comprobante_cobro)}
                        </td>
                        <td className={`px-4 py-3 text-right font-mono font-semibold ${esAnulada ? 'text-slate-400 line-through' : 'text-green-700'}`}>
                          ${parseFloat(c.monto_comprobante_cobro || 0).toFixed(2)}
                        </td>
                        <td className="px-4 py-3 text-slate-700">{c.nombre_forma_pago || '-'}</td>
                        <td className="px-4 py-3 text-center">
                          <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${
                            esAnulada
                              ? 'bg-red-100 text-red-700'
                              : 'bg-green-100 text-green-700'
                          }`}>
                            {c.estado_comprobante_cobro || '-'}
                          </span>
                        </td>
                        <td className="px-4 py-3 text-slate-500 text-xs max-w-xs truncate">
                          {c.observacion_comprobante_cobro || '-'}
                        </td>
                        <td className="px-4 py-3 text-center">
                          {!esAnulada && (
                            <button
                              onClick={() => abrirAnulacion(c)}
                              title="Anular comprobante"
                              className="inline-flex items-center gap-1 px-2.5 py-1 text-xs font-medium text-red-600 bg-red-50 hover:bg-red-100 border border-red-200 rounded-md transition-colors"
                            >
                              <i className="fas fa-ban"></i> Anular
                            </button>
                          )}
                          {esAnulada && (
                            <span className="text-xs text-slate-400 italic">Anulado</span>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Footer con totales */}
        {!loading && cobros.length > 0 && (
          <div className="flex-shrink-0 border-t border-slate-200 px-6 py-3 bg-slate-50 flex items-center justify-between">
            <span className="text-sm text-slate-500">{cobros.length} cobro(s) registrado(s)</span>
            <div className="flex items-center gap-2">
              <span className="text-sm font-semibold text-slate-600">Total cobrado (vigente):</span>
              <span className="text-lg font-bold text-green-700">${totalCobrado.toFixed(2)}</span>
            </div>
          </div>
        )}

        <div className="flex-shrink-0 border-t border-slate-100 px-6 py-3 flex justify-end">
          <button
            onClick={onClose}
            className="px-5 py-2 bg-slate-700 hover:bg-slate-800 text-white rounded-md font-medium transition-colors text-sm"
          >
            Cerrar
          </button>
        </div>
      </div>

      {/* Sub-modal de Anulación — idéntico a AnularComprobanteCobro.js de ExtJS */}
      {anularModal.open && anularModal.cobro && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/50">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="bg-red-700 px-5 py-4 flex items-center justify-between">
              <h3 className="text-white font-bold flex items-center gap-2">
                <i className="fas fa-ban"></i> ANULAR COMPROBANTE
              </h3>
              <button
                onClick={() => setAnularModal({ open: false, cobro: null })}
                className="text-red-200 hover:text-white transition-colors"
                disabled={anulando}
              >
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 flex flex-col gap-4">
              <div className="bg-red-50 border border-red-200 rounded-lg p-3 text-sm text-red-700">
                <p>Está por anular el comprobante de cobro por:</p>
                <p className="font-bold text-base mt-1">
                  ${parseFloat(anularModal.cobro.monto_comprobante_cobro || 0).toFixed(2)} — {anularModal.cobro.nombre_forma_pago}
                </p>
                <p className="text-xs mt-1 text-red-500">Esta acción no se puede deshacer.</p>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">
                  Motivo de Anulación <span className="text-red-500">*</span>
                </label>
                <textarea
                  rows={3}
                  className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-red-400 uppercase resize-none"
                  placeholder="Ingrese el motivo de la anulación..."
                  value={motivoAnulacion}
                  onChange={(e) => setMotivoAnulacion(e.target.value)}
                  disabled={anulando}
                />
              </div>
              <div className="flex items-center justify-end gap-3 pt-2 border-t border-slate-100">
                <button
                  type="button"
                  onClick={() => setAnularModal({ open: false, cobro: null })}
                  className="px-4 py-2 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-md font-medium text-sm transition-colors"
                  disabled={anulando}
                >
                  Cancelar
                </button>
                <button
                  type="button"
                  onClick={confirmarAnulacion}
                  className="px-5 py-2 bg-red-600 hover:bg-red-700 text-white rounded-md font-medium text-sm shadow-sm transition-colors flex items-center gap-2"
                  disabled={anulando}
                >
                  {anulando ? (
                    <><i className="fas fa-spinner fa-spin"></i> Anulando...</>
                  ) : (
                    <><i className="fas fa-ban"></i> Confirmar Anulación</>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Sub-modal de Anulación de TODA LA GUIA */}
      {anularGuiaModal.open && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/50">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="bg-red-800 px-5 py-4 flex items-center justify-between">
              <h3 className="text-white font-bold flex items-center gap-2">
                <i className="fas fa-radiation"></i> ANULAR GUÍA COMPLETA
              </h3>
              <button
                onClick={() => setAnularGuiaModal({ open: false })}
                className="text-red-200 hover:text-white transition-colors"
                disabled={anulando}
              >
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 flex flex-col gap-4">
              <div className="bg-red-50 border border-red-200 rounded-lg p-3 text-sm text-red-700">
                <p>Está a punto de anular la guía completa:</p>
                <p className="font-bold text-base mt-1">
                  Guía #{guia.numero_guia_final || guia.numero_guia || guia.id_guia}
                </p>
                <p className="text-xs mt-2 font-bold text-red-600 bg-red-100 p-2 rounded">
                  <i className="fas fa-exclamation-triangle mr-1"></i>
                  Esta acción anulará la guía y todos los registros asociados definitivamente.
                </p>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">
                  Motivo de Anulación de la Guía <span className="text-red-500">*</span>
                </label>
                <textarea
                  rows={3}
                  className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-red-400 uppercase resize-none"
                  placeholder="Ingrese el motivo por el cual anula la guía..."
                  value={motivoAnulacion}
                  onChange={(e) => setMotivoAnulacion(e.target.value)}
                  disabled={anulando}
                />
              </div>
              <div className="flex items-center justify-end gap-3 pt-2 border-t border-slate-100">
                <button
                  type="button"
                  onClick={() => setAnularGuiaModal({ open: false })}
                  className="px-4 py-2 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-md font-medium text-sm transition-colors"
                  disabled={anulando}
                >
                  Cancelar
                </button>
                <button
                  type="button"
                  onClick={confirmarAnulacionGuia}
                  className="px-5 py-2 bg-red-700 hover:bg-red-800 text-white rounded-md font-bold text-sm shadow-sm transition-colors flex items-center gap-2"
                  disabled={anulando}
                >
                  {anulando ? (
                    <><i className="fas fa-spinner fa-spin"></i> Anulando...</>
                  ) : (
                    <><i className="fas fa-skull-crossbones"></i> Confirmar</>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

