import React, { useState, useEffect, useRef } from 'react';
import { api, clienteApi } from '../../../config/axios';
import toast from 'react-hot-toast';

// Función para validar si hay una caja abierta
const validarCajaAbierta = async () => {
  try {
    // Intentar obtener id_caja_global del JWT (decodificado en el interceptor de axios)
    // o de localStorage como fallback
    const localCaja = localStorage.getItem('id_caja_global');
    if (localCaja) return localCaja;

    // Si no hay en localStorage, consultar al backend
    const res = await api.post('/caja/validarcaja');
    if (res.data?.success && res.data?.id_caja) {
      localStorage.setItem('id_caja_global', res.data.id_caja);
      return res.data.id_caja;
    }
    return null;
  } catch {
    return null;
  }
};

export const NuevaGuiaCompaniaForm = ({ initialData, onSubmit, onCancel }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  // Opciones de Selects
  const [companias, setCompanias] = useState([]);
  const [destinos, setDestinos] = useState([]);

  // Estado del Formulario
  const [formData, setFormData] = useState({
    numero_guia: '',
    compania_id: '',
    id_destino: '',
    porcentaje_comision: '',
    valor_neto: '',
    valor_comision: '',
    identificacion_cliente: '',
    nombre_cliente: '',
    monto_cobro: '',
    id_forma_pago: '1', // Efectivo por defecto
    detalle_pago: '',
    observacion_comprobante: '',
  });

  const [clienteBuscando, setClienteBuscando] = useState(false);
  const effectRan = useRef(false);

  useEffect(() => {
    if (!effectRan.current) {
      cargarCombos();
      effectRan.current = true;
    }
  }, []);

  const cargarCombos = async () => {
    try {
      // Cargar Compañías (Convenios)
      const resCompanias = await api.get('/companiaasociada/companiaasociadaSeleccionPaginadoCombo');
      if (resCompanias.data?.data) {
        setCompanias(resCompanias.data.data);
      }

      // Cargar Destinos (activos)
      const resDestinos = await api.get('/destino/destinoSeleccionCombo');
      if (resDestinos.data?.data) {
        setDestinos(resDestinos.data.data);
      }
    } catch (error) {
      console.error("Error al cargar combos:", error);
      toast.error("Error al cargar datos iniciales");
    }
  };

  const handleCompaniaChange = (e) => {
    const companiaId = e.target.value;
    const compania = companias.find(c => String(c.id_compania_asociada) === String(companiaId));

    let porcentaje = '';
    if (compania && compania.porcentaje_comision) {
      porcentaje = parseFloat(compania.porcentaje_comision).toString();
    } else if (compania) {
      toast.error('Esta compañía no tiene un porcentaje de comisión asignado');
    }

    setFormData(prev => {
      const newForm = { ...prev, compania_id: companiaId, porcentaje_comision: porcentaje };
      // Recalcular comisión si hay valor neto
      if (newForm.valor_neto && porcentaje) {
        newForm.valor_comision = ((parseFloat(newForm.valor_neto) * parseFloat(porcentaje)) / 100).toFixed(2);
        newForm.monto_cobro = newForm.valor_comision;
      } else {
        newForm.valor_comision = '';
        newForm.monto_cobro = '';
      }
      return newForm;
    });
  };

  const handleValorNetoChange = (e) => {
    const valorNeto = e.target.value;
    setFormData(prev => {
      const newForm = { ...prev, valor_neto: valorNeto };
      if (valorNeto && prev.porcentaje_comision) {
        newForm.valor_comision = ((parseFloat(valorNeto) * parseFloat(prev.porcentaje_comision)) / 100).toFixed(2);
        newForm.monto_cobro = newForm.valor_comision;
      } else {
        newForm.valor_comision = '';
        newForm.monto_cobro = '';
      }
      return newForm;
    });
  };

  const buscarClientePorIdentificacion = async (identificacion) => {
    if (!identificacion) return;
    setClienteBuscando(true);
    try {
      const res = await clienteApi.get('/cliente/clientebusquedaIdentificacion', {
        params: { identificacion_busqueda: identificacion }
      });
      if (res.data?.data && res.data.data.length > 0) {
        const cliente = res.data.data[0];
        setFormData(prev => ({
          ...prev,
          nombre_cliente: cliente.nombre_cliente || ''
        }));
        toast.success("Cliente encontrado");
      } else {
        toast.error("Cliente no encontrado, por favor escriba el nombre");
        setFormData(prev => ({ ...prev, nombre_cliente: '' }));
      }
    } catch (error) {
      toast.error("Error al buscar cliente");
    } finally {
      setClienteBuscando(false);
    }
  };

  const handleIdentificacionKeyDown = (e) => {
    if (e.key === 'Enter' || e.key === 'Tab') {
      if (e.key === 'Enter') e.preventDefault();
      buscarClientePorIdentificacion(formData.identificacion_cliente);
    }
  };

  const mostrarError = (msg) => {
    setErrorMsg(msg);
    toast.error(msg);
  };

  const handleNextStep = () => {
    setErrorMsg('');
    if (!formData.numero_guia || !formData.compania_id || !formData.id_destino || !formData.valor_neto || !formData.identificacion_cliente || !formData.nombre_cliente) {
      mostrarError("Por favor complete todos los campos obligatorios (*)");
      return;
    }
    if (!formData.valor_comision || parseFloat(formData.valor_comision) <= 0) {
      mostrarError("La comisión debe ser mayor a 0");
      return;
    }
    setStep(2);
  };

  const handleSubmit = async () => {
    setErrorMsg('');
    // Validaciones Paso 2
    if (!formData.monto_cobro || !formData.id_forma_pago) {
      mostrarError("Complete los datos de cobro");
      return;
    }

    // Validar que haya una caja abierta antes de enviar
    const cajaId = await validarCajaAbierta();
    if (!cajaId) {
      mostrarError('No tiene una caja abierta. Debe aperturar una caja primero.');
      return;
    }

    setLoading(true);
    setErrorMsg('');
    try {
      const payload = {
        ...formData,
        id_caja_global: cajaId,
        fecha_procesamiento: new Date().toISOString().slice(0, 19).replace('T', ' ')
      };

      const res = await api.post('/guias_companias/crear', payload);

      if (res.data?.success) {
        toast.success("Guía Compañía creada correctamente");
        if (onSubmit) onSubmit();
      } else {
        mostrarError(res.data?.error || res.data?.msg || "Error al crear la guía");
      }
    } catch (error) {
      mostrarError(error.response?.data?.error || error.response?.data?.msg || "Error de comunicación con el servidor");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Wizard Header */}
      <div className="flex items-center justify-between mb-6 border-b pb-4">
        <div className="flex space-x-4">
          <div className={`flex items-center ${step === 1 ? 'text-blue-600 font-bold' : 'text-gray-400'}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 mr-2 ${step === 1 ? 'border-blue-600 bg-blue-50' : 'border-gray-300'}`}>1</div>
            Info de la Guía
          </div>
          <div className="w-12 h-px bg-gray-300 my-auto"></div>
          <div className={`flex items-center ${step === 2 ? 'text-blue-600 font-bold' : 'text-gray-400'}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 mr-2 ${step === 2 ? 'border-blue-600 bg-blue-50' : 'border-gray-300'}`}>2</div>
            Información del Cobro
          </div>
        </div>
      </div>

      {/* Mensaje de error visible en el formulario */}
      {errorMsg && (
        <div className="mb-4 p-4 bg-red-50 border-2 border-red-300 rounded-lg flex items-start gap-3">
          <i className="fas fa-exclamation-circle text-red-500 mt-0.5"></i>
          <div>
            <p className="text-sm font-bold text-red-700">Error</p>
            <p className="text-sm text-red-600">{errorMsg}</p>
          </div>
          <button onClick={() => setErrorMsg('')} className="ml-auto text-red-400 hover:text-red-600">
            <i className="fas fa-times"></i>
          </button>
        </div>
      )}

      <div className="flex-1 overflow-y-auto pr-2">
        {step === 1 && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nº Guía *</label>
                <input
                  type="text"
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500 uppercase"
                  value={formData.numero_guia}
                  onChange={e => setFormData({ ...formData, numero_guia: e.target.value.toUpperCase() })}
                  placeholder="001-001-000000000"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Compañía *</label>
                <select
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500"
                  value={formData.compania_id}
                  onChange={handleCompaniaChange}
                >
                  <option value="">Seleccionar...</option>
                  {companias.map(c => (
                    <option key={c.id_compania_asociada} value={c.id_compania_asociada}>{c.nombre_compania_asociada}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Destino *</label>
                <select
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500"
                  value={formData.id_destino}
                  onChange={e => setFormData({ ...formData, id_destino: e.target.value })}
                >
                  <option value="">Seleccionar destino...</option>
                  {destinos.map(d => (
                    <option key={d.id_destino} value={d.id_destino}>{d.lugar_destino}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
              <h4 className="font-semibold text-slate-700 mb-4 border-b pb-2">Valores</h4>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Porcentaje Comisión (%)</label>
                  <input
                    type="text"
                    className="w-full p-2 border rounded bg-gray-100"
                    value={formData.porcentaje_comision}
                    readOnly
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Valor Neto ($) *</label>
                  <input
                    type="number"
                    step="0.01"
                    className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500 font-bold"
                    value={formData.valor_neto}
                    onChange={handleValorNetoChange}
                    placeholder="0.00"
                  />
                </div>
                <div className="bg-green-50 border border-green-200 rounded p-2 text-center flex flex-col justify-center">
                  <span className="text-xs text-green-700 font-bold uppercase">Comisión a Cobrar</span>
                  <span className="text-2xl font-black text-green-600">
                    ${formData.valor_comision || '0.00'}
                  </span>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Cédula / RUC Cliente *</label>
                <div className="flex">
                  <input
                    type="text"
                    className="w-full p-2 border rounded-l focus:ring-blue-500 focus:border-blue-500"
                    value={formData.identificacion_cliente}
                    onChange={e => setFormData({ ...formData, identificacion_cliente: e.target.value.replace(/\D/g, '') })}
                    onKeyDown={handleIdentificacionKeyDown}
                    placeholder="Presione Enter para buscar"
                  />
                  <button 
                    type="button"
                    onClick={() => buscarClientePorIdentificacion(formData.identificacion_cliente)}
                    disabled={clienteBuscando}
                    className="bg-slate-200 px-3 border border-l-0 rounded-r text-slate-600 hover:bg-slate-300"
                  >
                    <i className={`fas ${clienteBuscando ? 'fa-spinner fa-spin' : 'fa-search'}`}></i>
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Razón Social Cliente *</label>
                <input
                  type="text"
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500 uppercase"
                  value={formData.nombre_cliente}
                  onChange={e => setFormData({ ...formData, nombre_cliente: e.target.value.toUpperCase() })}
                />
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <div className="bg-blue-50 p-4 rounded-lg border border-blue-200 text-center mb-6">
              <p className="text-blue-800 text-sm font-medium">TOTAL A COBRAR POR COMISIÓN</p>
              <p className="text-4xl font-black text-blue-600">${formData.monto_cobro}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Forma de Pago *</label>
                <select
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500"
                  value={formData.id_forma_pago}
                  onChange={e => setFormData({ ...formData, id_forma_pago: e.target.value })}
                >
                  <option value="1">Efectivo</option>
                  <option value="2">Transferencia / Depósito</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nº Comprobante / Detalle</label>
                <input
                  type="text"
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500 uppercase"
                  value={formData.detalle_pago}
                  onChange={e => setFormData({ ...formData, detalle_pago: e.target.value.toUpperCase() })}
                  disabled={formData.id_forma_pago === '1'}
                />
              </div>

              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-700 mb-1">Observaciones</label>
                <textarea
                  className="w-full p-2 border rounded focus:ring-blue-500 focus:border-blue-500 uppercase"
                  rows="3"
                  value={formData.observacion_comprobante}
                  onChange={e => setFormData({ ...formData, observacion_comprobante: e.target.value.toUpperCase() })}
                ></textarea>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="flex justify-between items-center mt-6 pt-4 border-t">
        {step === 1 ? (
          <button
            type="button"
            onClick={onCancel}
            className="px-4 py-2 border border-gray-300 rounded text-gray-700 hover:bg-gray-50"
          >
            Cancelar
          </button>
        ) : (
          <button
            type="button"
            onClick={() => { setErrorMsg(''); setStep(1); }}
            className="px-4 py-2 border border-gray-300 rounded text-gray-700 hover:bg-gray-50"
          >
            Atrás
          </button>
        )}

        {step === 1 ? (
          <button
            type="button"
            onClick={handleNextStep}
            className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 flex items-center"
          >
            Siguiente <i className="fas fa-chevron-right ml-2"></i>
          </button>
        ) : (
          <button
            type="button"
            onClick={handleSubmit}
            disabled={loading}
            className={`px-6 py-2 bg-green-600 text-white rounded font-bold hover:bg-green-700 flex items-center ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            {loading ? <i className="fas fa-spinner fa-spin mr-2"></i> : <i className="fas fa-save mr-2"></i>}
            Crear Guía Compañía
          </button>
        )}
      </div>
    </div>
  );
};

import { useState } from 'react';
import { GuiaService } from '../../../services/guia.service';
import { api, clienteApi } from '../../../config/axios';
import Modal from '../../../components/common/Modal';
import toast from 'react-hot-toast';

export const RemitenteDestinatarioForm = ({ tipo, cliente, onChange, onConvenioFound, remitenteId, onDestinatarioAutoFill, error }) => {
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newCliente, setNewCliente] = useState({
    identificacion_cliente: '',
    tipo_identificacion_cliente: '05',
    nombre_cliente: '',
    direccion_cliente: '',
    correo_cliente: '',
    telefono_cliente: ''
  });

  // ── Estado para el Modal de Edición ─────────────────
  const [showEditModal, setShowEditModal] = useState(false);
  const [editFormData, setEditFormData] = useState({
    id_cliente: null,
    identificacion_cliente: '',
    tipo_identificacion_cliente: '05',
    nombre_cliente: '',
    direccion_cliente: '',
    correo_cliente: '',
    telefono_cliente: ''
  });
  const [editLoading, setEditLoading] = useState(false);
  const [isForcedEdit, setIsForcedEdit] = useState(false);

  const iconColor = tipo === 'Remitente' ? '#3498db' : '#e67e22';
  const isRemitente = tipo === 'Remitente';
  const esConsumidorFinal = cliente?.id_cliente === 683 || cliente?.nombres === 'CONSUMIDOR FINAL';

  const handleSearch = async () => {
    if (!busqueda || busqueda.trim().length < 3) {
      toast.error('Ingrese al menos 3 caracteres para buscar');
      return;
    }
    // Validar solo dígitos para cédula/RUC
    if (!/^\d+$/.test(busqueda.trim())) {
      toast.error('La identificación debe contener solo números');
      return;
    }
    setLoading(true);
    try {
      const result = await GuiaService.buscarClientePorIdentificacion(busqueda.trim());
      if (result && result.data && result.data.length > 0) {
        const cli = result.data[0];
        const clienteData = {
          id_cliente: cli.id_cliente || cli.id,
          cedula: cli.identificacion_cliente || cli.cedula || cli.ruc_cliente,
          nombres: cli.nombre_cliente || cli.nombres || '',
          direccion: cli.direccion_cliente || cli.direccion || '',
          telefono: cli.telefono_cliente || cli.telefono || '',
          email: cli.email_cliente || cli.correo_cliente || cli.email || '',
          telefono2: cli.telefono2 || ''
        };

        if (!clienteData.email || !clienteData.telefono) {
          toast.error(`El ${tipo.toLowerCase()} no tiene correo o teléfono. Debe actualizarlos para continuar.`);
          setEditFormData({
            id_cliente: clienteData.id_cliente,
            identificacion_cliente: clienteData.cedula || '',
            tipo_identificacion_cliente: cli.tipo_identificacion || '05',
            nombre_cliente: clienteData.nombres || '',
            direccion_cliente: clienteData.direccion || '',
            telefono_cliente: clienteData.telefono || '',
            correo_cliente: clienteData.email || '',
            provincia: cli.provincia || '',
            canton: cli.canton || '',
            telefono2: clienteData.telefono2 || ''
          });
          setIsForcedEdit(true);
          setShowEditModal(true);
          return;
        }

        onChange(clienteData);

        // Si es remitente, autocompletar destinatario (ExtJS: params { cedula })
        if (isRemitente && onDestinatarioAutoFill && clienteData.cedula) {
          try {
            const ultDest = await GuiaService.getUltimoDestinatarioPorRemitente(clienteData.cedula);
            if (ultDest?.success && ultDest.data) {
              onDestinatarioAutoFill(ultDest.data);
            }
          } catch (e) {
          }
        }

        toast.success(`${tipo} encontrado: ${clienteData.nombres}`);
      } else {
        toast.error(`${tipo} no encontrado. Puede crear uno nuevo.`);
        setShowCreateForm(true);
        setNewCliente(prev => ({ ...prev, identificacion_cliente: busqueda.trim() }));
      }
    } catch (error) {
      console.error('Error buscando cliente:', error);
      toast.error('Error al buscar cliente en el servidor');
    } finally {
      setLoading(false);
    }
  };

  const handleCreateClient = async () => {
    if (!newCliente.nombre_cliente || !newCliente.identificacion_cliente) {
      toast.error('Identificación y Nombre son obligatorios');
      return;
    }
    if (!/^\d+$/.test(newCliente.identificacion_cliente)) {
      toast.error('La identificación debe contener solo números');
      return;
    }
    if (newCliente.correo_cliente && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(newCliente.correo_cliente)) {
      toast.error('Formato de correo inválido');
      return;
    }
    setLoading(true);
    try {
      await GuiaService.buscarClientePorIdentificacion(newCliente.identificacion_cliente);
      // El backend de ingresarActualizarCliente crea o actualiza
      await clienteApi.post('/cliente/ingresarActualizarCliente', {
        identificacion_cliente: newCliente.identificacion_cliente,
        tipo_identificacion_cliente: newCliente.tipo_identificacion_cliente,
        nombre_cliente: newCliente.nombre_cliente,
        direccion_cliente: newCliente.direccion_cliente,
        correo_cliente: newCliente.correo_cliente,
        telefono_cliente: newCliente.telefono_cliente
      });
      const clienteData = {
        id_cliente: null,
        cedula: newCliente.identificacion_cliente,
        nombres: newCliente.nombre_cliente,
        direccion: newCliente.direccion_cliente,
        telefono: newCliente.telefono_cliente,
        email: newCliente.correo_cliente,
        telefono2: newCliente.telefono2
      };
      onChange(clienteData);
      setShowCreateForm(false);
      toast.success(`${tipo} creado exitosamente`);
    } catch (error) {
      console.error('Error creando cliente:', error);
      toast.error('Error al crear el cliente');
    } finally {
      setLoading(false);
    }
  };

  const handleSaveEdit = async () => {
    if (!editFormData.nombre_cliente) {
      toast.error('El nombre es obligatorio');
      return;
    }
    if (!editFormData.telefono_cliente) {
      toast.error('El teléfono es obligatorio');
      return;
    }
    if (!editFormData.correo_cliente) {
      toast.error('El correo es obligatorio');
      return;
    }
    setEditLoading(true);
    try {
      const payload = {
        identificacion_cliente: editFormData.identificacion_cliente,
        tipo_identificacion_cliente: editFormData.tipo_identificacion_cliente,
        nombre_cliente: editFormData.nombre_cliente,
        direccion_cliente: editFormData.direccion_cliente,
        correo_cliente: editFormData.correo_cliente || editFormData.email_cliente || '',
        telefono_cliente: editFormData.telefono_cliente,
        fecha_nacimiento: editFormData.fecha_nacimiento || ''
      };
      await clienteApi.post('/cliente/actualizarCliente', payload);

      // Actualizar el estado local del cliente
      const clienteActualizado = {
        ...(cliente || {}),
        id_cliente: editFormData.id_cliente || cliente?.id_cliente,
        cedula: editFormData.identificacion_cliente,
        nombres: editFormData.nombre_cliente,
        direccion: editFormData.direccion_cliente,
        telefono: editFormData.telefono_cliente,
        email: editFormData.correo_cliente || editFormData.email_cliente || '',
        telefono2: editFormData.telefono2 || ''
      };
      onChange(clienteActualizado);

      if (isForcedEdit && isRemitente && onDestinatarioAutoFill && clienteActualizado.cedula) {
        try {
          const ultDest = await GuiaService.getUltimoDestinatarioPorRemitente(clienteActualizado.cedula);
          if (ultDest?.success && ultDest.data) {
            onDestinatarioAutoFill(ultDest.data);
          }
        } catch (e) {
        }
      }

      setShowEditModal(false);
      setIsForcedEdit(false);
      toast.success(`${tipo} actualizado exitosamente`);
    } catch (error) {
      console.error('Error actualizando cliente:', error);
      toast.error('Error al actualizar el cliente');
    } finally {
      setEditLoading(false);
    }
  };

  const inputClass = "w-full h-8 px-2 text-xs border border-slate-200 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-400 bg-white text-slate-700";
  const labelClass = "block text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1";

  return (
    <div className="ng-section bg-white" style={{ borderTop: `3px solid ${iconColor}`, outline: error ? '2px solid #ef4444' : undefined, outlineOffset: '-1px' }}>
      <h3 className="section-title">
        <i className={`fas fa-user`} style={{color: iconColor, marginRight: '8px'}}></i>
        {tipo}
      </h3>

      {!cliente ? (
        <div className="search-client-box">
          {!showCreateForm ? (
            <>
              <div className="form-group" style={{ flex: 1 }}>
                <label>{isRemitente ? 'Cédula / RUC del Remitente' : 'Cédula / RUC del Destinatario'}</label>
                <div style={{ display: 'flex', gap: '8px' }}>
                  <input 
                    type="text" 
                    className={inputClass}
                    placeholder="Ingrese número de identificación" 
                    value={busqueda} 
                    onChange={(e) => setBusqueda(e.target.value.replace(/\D/g, ''))} 
                    onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                    disabled={loading}
                    maxLength={13}
                  />
                  <button type="button" className="btn-primary" onClick={handleSearch} disabled={loading} style={{ minWidth: '36px' }}>
                    {loading ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-search"></i>}
                  </button>
                </div>
              </div>
              <button type="button" className="btn-link" onClick={() => { setShowCreateForm(true); setNewCliente(prev => ({ ...prev, identificacion_cliente: busqueda })); }} style={{ fontSize: '11px', color: iconColor, marginTop: '4px' }}>
                <i className="fas fa-plus-circle"></i> Crear nuevo {tipo.toLowerCase()}
              </button>
              {!isRemitente && (
                <button type="button" className="btn-link" onClick={() => {
                  onChange({
                    id_cliente: 683,
                    cedula: '9999999999999',
                    nombres: 'CONSUMIDOR FINAL',
                    direccion: 'S/D',
                    telefono: '9999999999',
                    email: 'sincorreo@gmail.com',
                    telefono2: ''
                  });
                  toast.success('Consumidor Final seleccionado');
                }} style={{ fontSize: '11px', color: '#dc2626', marginTop: '4px', marginLeft: '8px' }}>
                  <i className="fas fa-user-check"></i> Consumidor Final
                </button>
              )}
            </>
          ) : (
            /* Formulario de creación rápida */
            <div className="create-client-form" style={{ padding: '10px', background: '#f8fafc', borderRadius: '8px' }}>
              <h4 style={{ fontSize: '12px', fontWeight: 700, marginBottom: '8px', color: '#334155' }}>
                <i className="fas fa-user-plus"></i> Crear {tipo}
              </h4>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px' }}>
                <div>
                  <label className={labelClass}>Identificación *</label>
                  <input className={inputClass} value={newCliente.identificacion_cliente} 
                    onChange={(e) => setNewCliente({...newCliente, identificacion_cliente: e.target.value.replace(/\D/g, '')})} />
                </div>
                <div>
