            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { api } from '../../config/axios';
import Swal from 'sweetalert2';
import Modal from '../../components/common/Modal';
import SocioBusSelector from '../../components/common/SocioBusSelector';
import { cobrosService } from '../../services/cobros.service';

const formatCurrency = (v) => `$${parseFloat(v || 0).toFixed(2)}`;
const formatFecha = (f) => f ? (f.split('T')[0] || f.split(' ')[0]) : '-';
const capitalize = (s) => s ? s.charAt(0).toUpperCase() + s.slice(1) : '';
const TIPOS_MULTA = ['Uniforme', 'Corbata', 'Incumplimiento de frecuencia', 'Incumplimiento de ruta', 'Otra'];

const NuevaMultaModal = ({ onClose, onSuccess }) => {
  const [form, setForm] = useState({ id_socio: '', id_bus: '', tipo_multa: '', valor: '10', observacion: '' });
  const [loading, setLoading] = useState(false);

  const handleChange = (field, value) => setForm(f => ({ ...f, [field]: value }));

  const handleSubmit = async () => {
    const { id_socio, id_bus, tipo_multa, valor } = form;
    if (!id_socio || !id_bus || !tipo_multa || !valor) { Swal.fire('Validación', 'Complete todos los campos', 'warning'); return; }
    setLoading(true);
    try {
      const res = await cobrosService.agregarMulta({ ...form, concepto: `Multa por ${form.tipo_multa}` });
      if (res.success) {
        Swal.fire('Éxito', 'Multa registrada', 'success');
        if (res.notificacion?.telefono) {
          api.post('/whatsapp/enviar', { number: res.notificacion.telefono, message: res.notificacion.mensaje }).catch(() => {});
        }
        onSuccess();
      } else Swal.fire('Error', res.message, 'error');
    } catch (err) { Swal.fire('Error', err.message, 'error'); }
    finally { setLoading(false); }
  };

  return (
    <Modal isOpen={true} onClose={onClose} title="Nueva Multa" width="max-w-md">
      <div className="space-y-4">
        <SocioBusSelector
          idSocio={form.id_socio} idBus={form.id_bus}
          onSocioChange={v => handleChange('id_socio', v)}
          onBusChange={v => handleChange('id_bus', v)}
        />
        <div>
          <label className="block text-[11px] font-bold text-slate-600 mb-1">Tipo de Multa</label>
          <select className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm" value={form.tipo_multa} onChange={e => handleChange('tipo_multa', e.target.value)}>
            <option value="">Seleccione...</option>
            {TIPOS_MULTA.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-[11px] font-bold text-slate-600 mb-1">Valor ($)</label>
          <input type="number" step="0.01" className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm font-bold" value={form.valor} onChange={e => handleChange('valor', e.target.value)} />
        </div>
        <div>
          <label className="block text-[11px] font-bold text-slate-600 mb-1">Observación</label>
          <textarea className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm" rows={3} value={form.observacion} onChange={e => handleChange('observacion', e.target.value)} />
        </div>
        <div className="flex justify-end gap-3 pt-2">
          <button onClick={onClose} disabled={loading} className="px-4 py-2 text-sm border border-slate-300 rounded-lg hover:bg-slate-50">Cancelar</button>
          <button onClick={handleSubmit} disabled={loading} className="px-4 py-2 text-sm bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg disabled:opacity-50 flex items-center gap-2">
            {loading ? <><i className="fas fa-spinner fa-spin"></i> Guardando...</> : <><i className="fas fa-save"></i> Guardar</>}
          </button>
        </div>
      </div>
    </Modal>
  );
};

export const MultasPage = () => {
  const [data, setData] = useState([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [pageSize] = useState(25);
  const [loading, setLoading] = useState(false);
  const [filtros, setFiltros] = useState({ id_socio: '', id_bus: '', estado: '', fecha_desde: '', fecha_hasta: '' });
  const [showModal, setShowModal] = useState(false);

  const hoyStr = new Date().toISOString().split('T')[0];

  const loadData = async () => {
    setLoading(true);
    try {
      const params = { limit: pageSize, page, ...Object.fromEntries(Object.entries(filtros).filter(([, v]) => v)) };
      const res = await cobrosService.listarMultas(params);
      if (res.success) { setData(res.data); setTotal(res.total); }
    } finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, [page, filtros]);

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-6">
      {showModal && <NuevaMultaModal onClose={() => setShowModal(false)} onSuccess={() => { setShowModal(false); loadData(); }} />}

      <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
        <i className="fas fa-gavel text-red-600"></i> Multas
      </h1>

      <div className="flex items-center gap-2">
        <button onClick={() => setShowModal(true)} className="px-4 py-2 bg-red-600 text-white text-sm font-bold rounded-lg hover:bg-red-700 flex items-center gap-2">
          <i className="fas fa-plus-circle"></i> Nueva Multa
        </button>
      </div>

      {/* ─── FILTROS ──────────────────────────────────────── */}
      <div className="bg-white border border-slate-200 rounded-lg p-4">
