import React, { useState, useEffect } from 'react';
import ProvinciaList from './components/ProvinciaList';
import ProvinciaSearchBar from './components/ProvinciaSearchBar';
import NewProvinciaForm from './components/NewProvinciaForm';
import Modal from '../../components/common/Modal';
import Swal from 'sweetalert2';
import { getProvincias, createProvincia, updateProvincia, deleteProvincia } from '../../services/provincia.service';

const ProvinciaPage = () => {
  const [provincias, setProvincias] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [editingProvincia, setEditingProvincia] = useState(null);
  const [filters, setFilters] = useState({ nombre: '' });
  const [pagination, setPagination] = useState({ currentPage: 1, totalPages: 1, pageSize: 25 });

  const fetchProvincias = async (currentFilters, currentPage) => {
    setLoading(true);
    try {
      const params = {
        nombre: currentFilters.nombre,
        page: currentPage,
        limit: pagination.pageSize,
      };
      const response = await getProvincias(params);
      setProvincias(response.data);
      setPagination((prev) => ({ ...prev, totalPages: Math.ceil(response.total / prev.pageSize) }));
    } catch (err) {
      setError(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProvincias(filters, pagination.currentPage);
  }, [filters, pagination.currentPage]);

  const handleSearch = (newFilters) => {
    setFilters(newFilters);
    setPagination((prev) => ({ ...prev, currentPage: 1 }));
  };

  const handleRefresh = () => {
    setFilters({ nombre: '' });
    setPagination({ currentPage: 1, totalPages: 1, pageSize: 25 });
  };

  const handlePageChange = (newPage) => {
    if (newPage > 0 && newPage <= pagination.totalPages) {
      setPagination((prev) => ({ ...prev, currentPage: newPage }));
    }
  };

  const handleNewProvinciaClick = () => {
    setEditingProvincia(null);
    setShowModal(true);
  };

  const handleEditProvincia = (provincia) => {
    setEditingProvincia(provincia);
    setShowModal(true);
  };

  const handleDeleteProvincia = async (id) => {
    const result = await Swal.fire({
      title: 'Confirmar',
      text: '¿Está seguro de que desea eliminar esta provincia?',
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: 'Sí, eliminar',
      cancelButtonText: 'Cancelar'
    });
    if (result.isConfirmed) {
      try {
        await deleteProvincia(id);
        fetchProvincias(filters, pagination.currentPage);
      } catch (err) {
        setError(err);
      }
    }
  };

  const handleSubmitForm = async (formData) => {
    try {
      if (formData.id_provincia) {
        await updateProvincia(formData);
      } else {
        await createProvincia(formData);
      }
      setShowModal(false);
      fetchProvincias(filters, pagination.currentPage);
    } catch (err) {
      setError(err);
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setEditingProvincia(null);
  };

  if (loading) return <p>Cargando provincias...</p>;
  if (error) return <p>Error: {error.message}</p>;

  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold mb-4">Gestión de Provincias</h1>
      <button
        onClick={handleNewProvinciaClick}
        className="bg-green-500 hover:bg-green-700 text-white font-bold py-2 px-4 rounded mb-4"
      >
        Nueva Provincia
      </button>
      <ProvinciaSearchBar onSearch={handleSearch} onRefresh={handleRefresh} />
      <ProvinciaList
        provincias={provincias}
        onEdit={handleEditProvincia}
        onDelete={handleDeleteProvincia}
        onPageChange={handlePageChange}
        currentPage={pagination.currentPage}
        totalPages={pagination.totalPages}
      />

      {showModal && (
        <Modal title={editingProvincia ? 'Editar Provincia' : 'Nueva Provincia'} onClose={handleCloseModal}>
          <NewProvinciaForm
            initialData={editingProvincia}
            onSubmit={handleSubmitForm}
            onCancel={handleCloseModal}
          />
        </Modal>
      )}
    </div>
  );
};

export default ProvinciaPage;

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { api } from '../../../config/axios';
import toast from 'react-hot-toast';

const NewProvinciaForm = ({ initialData, onSubmit, onCancel }) => {
  const isEditing = !!initialData;
  const [loading, setLoading] = useState(false);

  const { register, handleSubmit, formState: { errors }, reset } = useForm({
    defaultValues: {
      nombre_provincia: initialData?.nombre_provincia || initialData?.pro_nombre || '',
    }
  });

  const onFormSubmit = async (data) => {
    setLoading(true);
    try {
      if (isEditing) {
        await api.post('/provincia/provinciaInsertarActualizar', {
          id_provincia: initialData.id_provincia,
          nombre_provincia: data.nombre_provincia,
        });
      } else {
        await api.post('/provincia/provinciaInsertarActualizar', {
          nombre_provincia: data.nombre_provincia,
        });
      }
      toast.success(isEditing ? 'Provincia actualizada correctamente' : 'Provincia creada correctamente');
      onSubmit(data);
    } catch (err) {
      console.error('Error guardando provincia:', err);
      toast.error('Error al guardar la provincia. ' + (err.response?.data?.mensaje || err.message));
    } finally {
      setLoading(false);
    }
  };

  const inputClass = "w-full h-9 px-3 text-sm border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-400 transition-all bg-white text-slate-800";
  const labelClass = "block text-xs font-bold text-slate-600 uppercase tracking-wider mb-1.5";
  const errorClass = "text-rose-500 text-xs mt-1 flex items-center gap-1";

  return (
    <form onSubmit={handleSubmit(onFormSubmit)} className="space-y-5">
      <div className="space-y-4">
        {/* Nombre Provincia */}
        <div>
          <label className={labelClass}>
            Nombre de la Provincia <span className="text-rose-500">*</span>
          </label>
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <i className="fas fa-map text-slate-400"></i>
            </div>
            <input
              type="text"
              {...register('nombre_provincia', { required: 'El nombre es obligatorio' })}
              className={`${inputClass} pl-10 uppercase`}
              placeholder="Ej. PICHINCHA"
              autoFocus
            />
          </div>
          {errors.nombre_provincia && (
            <p className={errorClass}><i className="fas fa-exclamation-circle" />{errors.nombre_provincia.message}</p>
          )}
        </div>
      </div>

      {/* Botones */}
      <div className="flex justify-end gap-3 pt-5 border-t border-slate-100 mt-2">
        <button
          type="button"
          onClick={onCancel}
          className="px-5 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 text-sm font-bold transition-all"
        >
          <i className="fas fa-times mr-2" />Cancelar
        </button>
        <button
          type="submit"
          disabled={loading}
          className="px-5 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg text-sm font-bold transition-all shadow-sm disabled:opacity-70 flex items-center gap-2"
        >
          {loading
            ? <><i className="fas fa-spinner fa-spin" />Guardando...</>
            : <><i className="fas fa-save" />Guardar Provincia</>
          }
        </button>
      </div>
    </form>
  );
};

export default NewProvinciaForm;

